def skill_route_discovery_pass2_secondary_harness_checklist(
    *,
    raw_input: dict[str, Any],
    adjacent_general_agent_project_eval: dict[str, Any],
) -> dict[str, Any]:
    """Require local harness evidence before adjacent agent projects can affect pass 2."""

    window = raw_input.get("capability_window")
    window = window if isinstance(window, dict) else {}
    current_pass = int(window.get("current_pass") or 0)
    records = adjacent_general_agent_project_eval.get("records")
    records = records if isinstance(records, list) else []
    rows: list[dict[str, Any]] = []
    diagnostics: list[str] = []

    for index, raw_record in enumerate(records, start=1):
        record = raw_record if isinstance(raw_record, dict) else {}
        item_id = optional_string(record.get("item_id")) or f"adjacent-agent-record-{index}"
        source_hash = optional_string(record.get("source_url_hash")) or ""
        topic_codes = string_list(record.get("topics"))
        local_fixture = record.get("local_harness_fixture")
        local_fixture = local_fixture if isinstance(local_fixture, dict) else {}
        fixture_declared = bool(optional_string(local_fixture.get("fixture_path")))
        expected_behavior_declared = bool(
            optional_string(local_fixture.get("behavior"))
            or string_list(local_fixture.get("expected_behaviors"))
        )
        expected_output_declared = bool(
            optional_string(local_fixture.get("expected_output"))
            or string_list(local_fixture.get("expected_outputs"))
        )
        pass_fail_signal_declared = bool(
            optional_string(local_fixture.get("pass_fail_signal"))
            or string_list(local_fixture.get("assertions"))
        )
        rollback_path_declared = bool(optional_string(local_fixture.get("rollback_artifact")))
        non_secret_config_declared = local_fixture.get("non_secret_config") is True
        local_fixture_ready = all(
            (
                fixture_declared,
                expected_behavior_declared,
                expected_output_declared,
                pass_fail_signal_declared,
                rollback_path_declared,
                non_secret_config_declared,
            )
        )
        row_diagnostics = []
        if not fixture_declared:
            row_diagnostics.append("local_harness_fixture_missing")
        if not expected_behavior_declared:
            row_diagnostics.append("expected_behavior_missing")
        if not expected_output_declared:
            row_diagnostics.append("expected_output_missing")
        if not pass_fail_signal_declared:
            row_diagnostics.append("pass_fail_signal_missing")
        if not rollback_path_declared:
            row_diagnostics.append("rollback_path_missing")
        if not non_secret_config_declared:
            row_diagnostics.append("non_secret_config_missing")
        diagnostics.extend(f"{stable_text_hash(item_id)}:{diagnostic}" for diagnostic in row_diagnostics)

        rows.append(
            {
                "item_id": item_id,
                "source_hash": source_hash,
                "evaluation_lane": "agent_harness_eval_required",
                "activation_status": "local_harness_fixture_ready"
                if local_fixture_ready
                else "blocked_until_local_agent_harness_fixture",
                "skill_route_discovery_inherited": False,
                "minimal_fixture": {
                    "behavior": "agent_harness_eval_lane",
                    "required_fixture_fields": [
                        "fixture_path",
                        "expected_behavior",
                        "expected_output",
                        "pass_fail_signal",
                        "rollback_artifact",
                        "non_secret_config",
                    ],
                    "runnable_scenario_required": True,
                    "expected_output_required": True,
                    "pass_fail_signal_required": True,
                    "rollback_path_required": True,
                    "non_secret_config_required": True,
                },
                "fixture_intake": {
                    "intake_id": stable_text_hash(
                        "|".join(
                            [
                                item_id,
                                source_hash,
                                ",".join(sorted(topic_codes)),
                            ]
                        )
                    ),
                    "intake_status": "ready_for_local_harness_eval"
                    if local_fixture_ready
                    else "blocked_until_fixture_fields_declared",
                    "next_local_action": "run_declared_agent_harness_fixture"
                    if local_fixture_ready
                    else "declare_agent_harness_eval_fixture",
                    "required_fixture_fields": [
                        "fixture_path",
                        "expected_behavior",
                        "expected_output",
                        "pass_fail_signal",
                        "rollback_artifact",
                        "non_secret_config",
                    ],
                    "missing_fixture_fields": list(row_diagnostics),
                    "route_reason_codes": sorted(topic_codes),
                    "source_ref_mode": "source_url_hash_only",
                    "source_hash": source_hash,
                    "local_corroboration_required": True,
                    "implementation_patch_allowed": False,
                    "runtime_action": "none",
                    "runtime_action_allowed": False,
                    "external_harness_execution_allowed": False,
                    "provider_runtime_launch_allowed": False,
                    "remote_execution_allowed": False,
                    "raw_source_url_exported": False,
                    "raw_upstream_body_exported": False,
                },
                "acceptance_gates": {
                    "local_fixture_declared": fixture_declared,
                    "expected_behavior_declared": expected_behavior_declared,
                    "expected_output_declared": expected_output_declared,
                    "pass_fail_signal_declared": pass_fail_signal_declared,
                    "rollback_path_declared": rollback_path_declared,
                    "non_secret_config_declared": non_secret_config_declared,
                    "skill_route_discovery_not_inherited": True,
                    "external_harness_execution_denied": True,
                    "provider_runtime_launch_denied": True,
                    "remote_execution_denied": True,
                    "raw_source_url_not_exported": True,
                    "raw_upstream_body_not_exported": True,
                },
                "row_diagnostics": row_diagnostics,
                "required_validation": [SKILL_ROUTE_DISCOVERY_PREACTIVATION_HARNESS_COMMAND],
                "local_validation_required": True,
                "local_corroboration_required": True,
                "body_free": True,
                "runtime_action": "none",
                "runtime_action_allowed": False,
                "implementation_patch_allowed": False,
                "external_skill_activation_allowed": False,
                "external_agent_activation_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_source_url_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    present = bool(rows)
    fixture_intake_rows = [
        {
            "item_id": row["item_id"],
            "source_ref_mode": "source_url_hash_only",
            "source_hash": row["source_hash"],
            "evaluation_lane": row["evaluation_lane"],
            "activation_status": row["activation_status"],
            "fixture_intake": row["fixture_intake"],
            "acceptance_gates": row["acceptance_gates"],
            "row_diagnostics": row["row_diagnostics"],
            "local_corroboration_required": True,
            "implementation_patch_allowed": False,
            "runtime_action": "none",
            "runtime_action_allowed": False,
            "external_harness_execution_allowed": False,
            "provider_runtime_launch_allowed": False,
            "remote_execution_allowed": False,
            "raw_source_url_exported": False,
            "raw_upstream_body_exported": False,
        }
        for row in rows
    ]
    return {
        "controller_surface": "skill_route_discovery_pass2_secondary_harness_checklist",
        "status": "ready" if current_pass == 2 and present else "not_present" if not present else "not_applicable",
        "decision": "hold_adjacent_agent_projects_for_local_harness_fixture"
        if present
        else "no_adjacent_agent_project_checklist_required",
        "current_pass": current_pass,
        "record_count": len(rows),
        "ready_fixture_count": sum(
            1 for row in rows if row["activation_status"] == "local_harness_fixture_ready"
        ),
        "blocked_fixture_count": sum(
            1
            for row in rows
            if row["activation_status"] == "blocked_until_local_agent_harness_fixture"
        ),
        "agent_harness_eval_required": present,
        "skill_route_discovery_inherited": False,
        "local_eval_activation_allowed": False,
        "fixture_requirements": [
            "runnable_scenario",
            "expected_output",
            "pass_fail_signal",
            "rollback_path",
            "non_secret_config",
        ],
        "local_harness_fixture_intake_queue": {
            "controller_surface": "skill_route_discovery_pass2_local_harness_fixture_intake_queue",
            "status": "ready" if current_pass == 2 and present else "not_present" if not present else "not_applicable",
            "decision": "declare_local_agent_harness_fixture_before_implementation_patch"
            if present
            else "no_local_harness_fixture_intake_required",
            "queue_scope": "adjacent_general_agent_projects_only",
            "work_item_count": len(fixture_intake_rows),
            "ready_fixture_count": sum(
                1
                for row in fixture_intake_rows
                if row["activation_status"] == "local_harness_fixture_ready"
            ),
            "blocked_fixture_count": sum(
                1
                for row in fixture_intake_rows
                if row["activation_status"] == "blocked_until_local_agent_harness_fixture"
            ),
            "blocked_before_implementation_patch_count": len(fixture_intake_rows),
            "required_fixture_fields": [
                "fixture_path",
                "expected_behavior",
                "expected_output",
                "pass_fail_signal",
                "rollback_artifact",
                "non_secret_config",
            ],
            "required_validation": [SKILL_ROUTE_DISCOVERY_PREACTIVATION_HARNESS_COMMAND] if present else [],
            "rows": fixture_intake_rows,
            "local_corroboration_required": present,
            "implementation_patch_allowed": False,
            "local_validation_required": present,
            "body_free": True,
            "runtime_action": "none",
            "runtime_action_allowed": False,
            "external_harness_execution_allowed": False,
            "provider_runtime_launch_allowed": False,
            "remote_execution_allowed": False,
            "raw_source_urls_exported": False,
            "raw_upstream_body_exported": False,
        },
        "rows": rows,
        "diagnostics": sorted(dict.fromkeys(diagnostics)),
        "required_validation": [SKILL_ROUTE_DISCOVERY_PREACTIVATION_HARNESS_COMMAND] if present else [],
        "local_validation_required": present,
        "local_corroboration_required": present,
        "body_free": True,
        "runtime_action_allowed": False,
        "implementation_patch_allowed": False,
        "external_skill_activation_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_source_urls_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass2_operator_validation_manifest(
    *,
    pass2_handoff_packet: dict[str, Any],
    validation_work_queue: dict[str, Any],
) -> dict[str, Any]:
    """Render pass-2 route evidence as bounded local work an operator can replay."""

    allowed_lanes = string_list(pass2_handoff_packet.get("allowed_local_lanes"))
    activation_candidate = pass2_handoff_packet.get("activation_candidate_lane")
    activation_candidate = activation_candidate if isinstance(activation_candidate, dict) else {}
    candidate_rows_input = activation_candidate.get("rows")
    candidate_rows_input = candidate_rows_input if isinstance(candidate_rows_input, list) else []
    work_rows_input = validation_work_queue.get("rows")
    work_rows_input = work_rows_input if isinstance(work_rows_input, list) else []
    work_rows_by_lane: dict[str, list[dict[str, Any]]] = {}
    for work_row in work_rows_input:
        if not isinstance(work_row, dict):
            continue
        lane = optional_string(work_row.get("selected_local_lane")) or ""
        if lane:
            work_rows_by_lane.setdefault(lane, []).append(work_row)

    rows: list[dict[str, Any]] = []
    diagnostics: list[str] = []
    for index, raw_row in enumerate(candidate_rows_input):
        row = raw_row if isinstance(raw_row, dict) else {}
        selected_lane = optional_string(row.get("selected_local_lane")) or ""
        local_artifact_review = row.get("local_artifact_review")
        local_artifact_review = local_artifact_review if isinstance(local_artifact_review, dict) else {}
        work_rows = work_rows_by_lane.get(selected_lane, [])
        route_profiles = string_list(row.get("route_profiles"))
        row_diagnostics = string_list(row.get("diagnostics"))
        if selected_lane not in allowed_lanes:
            row_diagnostics.append("selected_local_lane_not_allowed")
        if row.get("candidate_status") != "ready":
            row_diagnostics.append("activation_candidate_not_ready")
        if not route_profiles:
            row_diagnostics.append("route_profiles_missing")
        if not work_rows:
            row_diagnostics.append("validation_work_queue_mapping_missing")
        if row.get("local_validation_required") is not True:
            row_diagnostics.append("local_validation_not_required")
        if str(row.get("runtime_action") or "none") != "none":
            row_diagnostics.append("runtime_action_requested")
        if row.get("external_skill_activation_allowed") is not False:
            row_diagnostics.append("external_skill_activation_not_denied")
        if row.get("external_harness_execution_allowed") is not False:
            row_diagnostics.append("external_harness_execution_not_denied")
        local_artifact_status = (
            optional_string(local_artifact_review.get("status"))
            or optional_string(row.get("local_artifact_review_status"))
            or ""
        )
        if local_artifact_status != "ready":
            row_diagnostics.append("local_artifact_review_not_ready")

        row_diagnostics = sorted(dict.fromkeys(item for item in row_diagnostics if item))
        diagnostics.extend(f"rows[{index}].{diagnostic}" for diagnostic in row_diagnostics)
        rows.append(
            {
                "manifest_row_id": stable_text_hash(
                    "|".join(
                        [
                            selected_lane,
                            ",".join(route_profiles),
                            str(row.get("queue_fingerprint") or ""),
                        ]
                    )
                ),
                "queue_role": optional_string(row.get("queue_role")) or "",
                "selected_local_lane": selected_lane,
                "route_profiles": route_profiles,
                "validation_scope": optional_string(row.get("validation_scope"))
                or (f"local_{selected_lane}_lane_only" if selected_lane else "none"),
                "profile_validation_gates": string_list(row.get("profile_validation_gates")),
                "artifact_contract_kind": optional_string(row.get("artifact_contract_kind")) or selected_lane,
                "target_path_count": int(row.get("target_path_count") or 0),
                "target_path_hashes": string_list(row.get("target_path_hashes")),
                "operator_review_requirements": string_list(row.get("operator_review_requirements")),
                "required_validation": string_list(row.get("required_validation")),
                "provider_runtime_replay_commands": string_list(row.get("provider_runtime_replay_commands")),
                "evidence_ref_mode": "selected_item_ids_only",
                "evidence_item_count": int(row.get("evidence_item_id_count") or 0),
                "candidate_source_count": int(row.get("candidate_source_count") or 0),
                "work_queue_item_count": len(work_rows),
                "work_queue_item_ids": [
                    str(work_row.get("work_item_id") or "") for work_row in work_rows if work_row.get("work_item_id")
                ],
                "status": "ready" if not row_diagnostics else "blocked",
                "diagnostics": row_diagnostics,
                "local_validation_required": True,
                "body_free": True,
                "runtime_action": "none",
                "runtime_action_allowed": False,
                "external_skill_activation_allowed": False,
                "external_skill_code_allowed": False,
                "external_agent_activation_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_target_paths_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    pass2_ready = pass2_handoff_packet.get("status") == "ready"
    work_queue_ready = validation_work_queue.get("status") == "ready"
    ready = pass2_ready and work_queue_ready and bool(rows) and not diagnostics
    return {
        "controller_surface": "skill_route_discovery_pass2_operator_validation_manifest",
        "status": "ready" if ready else "blocked",
        "decision": "operator_can_validate_bounded_skill_routes_before_activation"
        if ready
        else "repair_pass2_operator_validation_manifest_before_activation",
        "manifest_scope": "pass2_selected_and_queued_local_lanes",
        "pass2_handoff_status": optional_string(pass2_handoff_packet.get("status")) or "",
        "validation_work_queue_status": optional_string(validation_work_queue.get("status")) or "",
        "allowed_local_lanes": allowed_lanes,
        "manifest_lane_count": len({row["selected_local_lane"] for row in rows if row["selected_local_lane"]}),
        "manifest_lanes": sorted({row["selected_local_lane"] for row in rows if row["selected_local_lane"]}),
        "covered_route_profiles": sorted(
            {
                profile
                for row in rows
                for profile in string_list(row.get("route_profiles"))
            }
        ),
        "row_count": len(rows),
        "ready_row_count": sum(1 for row in rows if row["status"] == "ready"),
        "blocked_row_count": sum(1 for row in rows if row["status"] != "ready"),
        "evidence_ref_mode": "selected_item_ids_only",
        "operator_review_requirements": [
            "changed_file_review",
            "focused_local_validation",
            "rollback_artifact",
            "review_note",
        ],
        "rows": rows,
        "diagnostics": sorted(dict.fromkeys(diagnostics)),
        "required_validation": skill_route_discovery_preactivation_validation_commands(),
        "local_validation_required": True,
        "body_free": True,
        "runtime_action": "none",
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_skill_code_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass3_handoff_packet(
    *,
    raw_input: dict[str, Any],
    current_action: dict[str, Any],
    pass_validation_replay_queue: dict[str, Any],
    mixed_local_lane_probe: dict[str, Any],
    profile_lane_acceptance_contract: dict[str, Any],
) -> dict[str, Any]:
    """Expose pass-3 continuation across mixed skill routes without adding lanes."""

    from blackhole_agent.skill_routing import SKILL_ROUTE_DISCOVERY_ALLOWED_LANES

    window = raw_input.get("capability_window")
    window = window if isinstance(window, dict) else {}
    current_pass = int(current_action.get("current_pass") or 0)
    total_passes = int(current_action.get("total_passes") or 0)
    queue_rows = pass_validation_replay_queue.get("rows")
    queue_rows = queue_rows if isinstance(queue_rows, list) else []
    allowed_lanes = set(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES)

    rows: list[dict[str, Any]] = []
    diagnostics: list[str] = []
    for raw_row in queue_rows:
        row = raw_row if isinstance(raw_row, dict) else {}
        selected_lane = optional_string(row.get("selected_local_lane")) or ""
        if selected_lane not in allowed_lanes:
            diagnostics.append("queued_lane_not_bounded")
            continue
        rows.append(
            {
                "queue_position": int(row.get("queue_position") or len(rows) + 1),
                "queue_role": optional_string(row.get("queue_role")) or "queued_bounded_lane",
                "selected_local_lane": selected_lane,
                "validation_scope": optional_string(row.get("validation_scope"))
                or f"local_{selected_lane}_lane_only",
                "route_profiles": string_list(row.get("route_profiles")),
                "route_profile_count": len(string_list(row.get("route_profiles"))),
                "evidence_ref_mode": "selected_item_ids_only",
                "evidence_item_ids": string_list(row.get("evidence_item_ids")),
                "evidence_item_id_count": len(string_list(row.get("evidence_item_ids"))),
                "candidate_source_hashes": string_list(row.get("candidate_source_hashes")),
                "candidate_source_count": len(string_list(row.get("candidate_source_hashes"))),
                "queue_fingerprint": optional_string(row.get("queue_fingerprint")) or "",
                "fingerprint_basis": optional_string(row.get("fingerprint_basis"))
                or "queue_role_lane_profiles_evidence_hashes",
                "replay_commands": string_list(row.get("replay_commands")),
                "provider_runtime_replay_commands": string_list(row.get("provider_runtime_replay_commands")),
                "local_validation_required": True,
                "runtime_action": "none",
                "external_skill_activation_allowed": False,
                "external_skill_code_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_target_paths_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    if pass_validation_replay_queue.get("status") != "ready":
        diagnostics.append("pass_validation_replay_queue_not_ready")
    mixed_probe_status = str(mixed_local_lane_probe.get("status") or "")
    mixed_probe_primary_route = optional_string(mixed_local_lane_probe.get("primary_route")) or "skill_route_discovery"
    mixed_probe_secondary_status = (
        optional_string(mixed_local_lane_probe.get("secondary_lane_status"))
        or "blocked_until_local_corroboration"
    )
    mixed_probe_bounded_review = (
        mixed_probe_status == "review"
        and mixed_probe_primary_route == "skill_route_discovery"
        and mixed_probe_secondary_status == "blocked_until_local_corroboration"
    )
    if mixed_probe_status not in {"ready", "blocked"} and not mixed_probe_bounded_review:
        diagnostics.append("mixed_local_lane_probe_review_required")
    if mixed_probe_status == "ready" and mixed_probe_primary_route != "skill_route_discovery":
        diagnostics.append("mixed_local_lane_primary_route_drift")
    profile_contract_status = optional_string(profile_lane_acceptance_contract.get("status")) or ""
    if profile_contract_status != "ready":
        diagnostics.append("profile_lane_acceptance_contract_not_ready")

    selected_rows = [row for row in rows if row["queue_role"] == "selected_current_pass_lane"]
    queued_rows = [row for row in rows if row["queue_role"] == "queued_bounded_lane"]
    ready = current_pass == 3 and total_passes >= 4 and bool(selected_rows) and not diagnostics
    route_profiles = sorted(
        {
            profile
            for row in rows
            for profile in string_list(row.get("route_profiles"))
        }
    )
    selected_lanes = sorted({row["selected_local_lane"] for row in selected_rows})
    queued_lanes = sorted({row["selected_local_lane"] for row in queued_rows})
    final_pass_replay_checklist = skill_route_discovery_pass3_final_pass_replay_checklist(
        ready=ready,
        current_action=current_action,
        selected_rows=selected_rows,
        queued_rows=queued_rows,
        mixed_probe_primary_route=mixed_probe_primary_route,
        mixed_probe_secondary_status=mixed_probe_secondary_status,
        diagnostics=diagnostics,
    )
    checkpoint_blockers = [] if ready else sorted(dict.fromkeys(diagnostics or ["pass3_handoff_not_ready"]))
    operator_checkpoints = [
        {
            "checkpoint": "replay_selected_current_pass_lane"
            if row["queue_role"] == "selected_current_pass_lane"
            else "carry_queued_bounded_lane_to_final_pass",
            "queue_position": row["queue_position"],
            "queue_role": row["queue_role"],
            "selected_local_lane": row["selected_local_lane"],
            "validation_scope": row["validation_scope"],
            "route_profiles": row["route_profiles"],
            "evidence_ref_mode": "selected_item_ids_only",
            "evidence_item_id_count": row["evidence_item_id_count"],
            "candidate_source_count": row["candidate_source_count"],
            "queue_fingerprint": row["queue_fingerprint"],
            "status": "ready" if ready else "blocked",
            "blockers": checkpoint_blockers,
            "required_validation": row["replay_commands"],
            "provider_runtime_replay_commands": row["provider_runtime_replay_commands"],
            "local_validation_required": True,
            "body_free": True,
            "runtime_action_allowed": False,
            "external_skill_activation_allowed": False,
            "external_skill_code_allowed": False,
            "external_agent_activation_allowed": False,
            "external_harness_execution_allowed": False,
            "provider_runtime_launch_allowed": False,
            "remote_execution_allowed": False,
            "raw_evidence_exported": False,
            "raw_evidence_urls_exported": False,
            "raw_source_urls_exported": False,
            "raw_target_paths_exported": False,
            "raw_upstream_body_exported": False,
        }
        for row in rows
    ]
    profile_activation_gates = skill_route_discovery_pass3_profile_activation_gates(
        ready=ready,
        rows=rows,
        mixed_probe_primary_route=mixed_probe_primary_route,
        mixed_probe_secondary_status=mixed_probe_secondary_status,
        profile_lane_acceptance_contract=profile_lane_acceptance_contract,
        diagnostics=diagnostics,
    )
    route_profile_lane_contract = skill_route_discovery_pass3_route_profile_lane_contract(
        ready=ready,
        current_action=current_action,
        profile_activation_gates=profile_activation_gates,
    )
    proposal_lane_activation_contract = skill_route_discovery_pass3_proposal_lane_activation_contract(
        ready=ready,
        raw_input=raw_input,
        route_profile_lane_contract=route_profile_lane_contract,
    )
    profile_validation_proof = skill_route_discovery_pass3_profile_validation_proof(
        ready=ready,
        raw_input=raw_input,
        rows=rows,
        profile_activation_gates=profile_activation_gates,
        diagnostics=diagnostics,
    )
    activation_proof_summary = skill_route_discovery_pass3_activation_proof_summary(
        ready=ready,
        profile_validation_proof=profile_validation_proof,
    )
    operator_checkpoint_list = {
        "controller_surface": "skill_route_discovery_pass3_operator_checkpoint_list",
        "status": "ready" if ready else "not_applicable" if current_pass != 3 else "blocked",
        "decision": "operator_can_replay_pass3_checkpoints"
        if ready
        else "repair_pass3_checkpoints_before_final_pass",
        "checkpoint_count": len(operator_checkpoints),
        "selected_checkpoint_count": len(selected_rows),
        "queued_checkpoint_count": len(queued_rows),
        "evidence_ref_mode": "selected_item_ids_only",
        "allowed_local_lanes": list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES),
        "rows": operator_checkpoints,
        "diagnostics": sorted(dict.fromkeys(diagnostics)),
        "local_validation_required": True,
        "body_free": True,
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_skill_code_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }
    promotion_runbook = skill_route_discovery_pass3_promotion_runbook(
        ready=ready,
        activation_proof_summary=activation_proof_summary,
        operator_checkpoint_list=operator_checkpoint_list,
        profile_validation_proof=profile_validation_proof,
    )
    local_validation_probe = skill_route_discovery_pass3_local_validation_probe(
        ready=ready,
        profile_activation_gates=profile_activation_gates,
        profile_validation_proof=profile_validation_proof,
        promotion_runbook=promotion_runbook,
    )
    runner_harness_control_plane = skill_route_discovery_pass3_control_plane(
        ready=ready,
        current_action=current_action,
        pass_validation_replay_queue=pass_validation_replay_queue,
        operator_checkpoint_list=operator_checkpoint_list,
        profile_validation_proof=profile_validation_proof,
        activation_proof_summary=activation_proof_summary,
        promotion_runbook=promotion_runbook,
        diagnostics=diagnostics,
    )
    adjacent_general_agent_project_eval = (
        skill_route_discovery_pass3_adjacent_general_agent_project_eval(raw_input=raw_input)
    )

    return {
        "controller_surface": "skill_route_discovery_pass3_handoff_packet",
        "status": "ready" if ready else "not_applicable" if current_pass != 3 else "blocked",
        "decision": "continue_active_and_queued_bounded_lanes_to_final_pass"
        if ready
        else "repair_pass3_handoff_before_final_pass",
        "theme": optional_string(window.get("theme")) or optional_string(current_action.get("theme")) or "",
        "current_pass": current_pass,
        "next_pass": int(current_action.get("next_pass") or 0),
        "total_passes": total_passes,
        "allowed_local_lanes": list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES),
        "selected_local_lanes": selected_lanes,
        "queued_local_lanes": queued_lanes,
        "route_profiles": route_profiles,
        "route_profile_count": len(route_profiles),
        "queue_count": len(rows),
        "selected_queue_count": len(selected_rows),
        "queued_queue_count": len(queued_rows),
        "evidence_ref_mode": "selected_item_ids_only",
        "evidence_item_ids": sorted(
            {
                item_id
                for row in rows
                for item_id in string_list(row.get("evidence_item_ids"))
            }
        ),
        "candidate_source_hashes": sorted(
            {
                source_hash
                for row in rows
                for source_hash in string_list(row.get("candidate_source_hashes"))
            }
        ),
        "queue_fingerprints": [str(row["queue_fingerprint"]) for row in rows if row.get("queue_fingerprint")],
        "fingerprint_basis": "queue_role_lane_profiles_evidence_hashes",
        "mixed_skill_workflow_primary_route": mixed_probe_primary_route,
        "secondary_lane": optional_string(mixed_local_lane_probe.get("secondary_lane"))
        or "agent_harness_eval_after_local_corroboration",
        "secondary_lane_status": mixed_probe_secondary_status,
        "final_pass_replay_checklist": final_pass_replay_checklist,
        "profile_activation_gates": profile_activation_gates,
        "route_profile_lane_contract": route_profile_lane_contract,
        "proposal_lane_activation_contract": proposal_lane_activation_contract,
        "profile_validation_proof": profile_validation_proof,
        "activation_proof_summary": activation_proof_summary,
        "operator_checkpoint_list": operator_checkpoint_list,
        "promotion_runbook": promotion_runbook,
        "local_validation_probe": local_validation_probe,
        "runner_harness_control_plane": runner_harness_control_plane,
        "adjacent_general_agent_project_eval": adjacent_general_agent_project_eval,
        "rows": rows,
        "diagnostics": sorted(dict.fromkeys(diagnostics)),
        "required_validation": string_list(current_action.get("required_validation")),
        "provider_runtime_replay_commands": string_list(
            current_action.get("provider_runtime_replay_commands")
        ),
        "local_validation_required": True,
        "body_free": True,
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_skill_code_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass3_proposal_lane_activation_contract(
    *,
    ready: bool,
    raw_input: dict[str, Any],
    route_profile_lane_contract: dict[str, Any],
) -> dict[str, Any]:
    """Bind active pass-3 proposal IDs to bounded route-profile lanes."""

    from blackhole_agent.skill_routing import SKILL_ROUTE_DISCOVERY_ALLOWED_LANES

    window = raw_input.get("capability_window")
    window = window if isinstance(window, dict) else {}
    anchoring_proposals = string_list(window.get("anchoring_proposals"))
    active_skill_proposals = [
        proposal_id
        for proposal_id in anchoring_proposals
        if "agent-harness" not in proposal_id
        and "agentworld" not in proposal_id.lower()
        and "qwen" not in proposal_id.lower()
        and "looper" not in proposal_id.lower()
    ]
    adjacent_proposals = [
        proposal_id
        for proposal_id in anchoring_proposals
        if proposal_id not in active_skill_proposals
    ]

    profile_rows = route_profile_lane_contract.get("rows")
    profile_rows = profile_rows if isinstance(profile_rows, list) else []
    allowed_lanes = list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES)
    allowed_lane_set = set(allowed_lanes)
    rows: list[dict[str, Any]] = []
    diagnostics: list[str] = []

    for raw_row in profile_rows:
        profile_row = raw_row if isinstance(raw_row, dict) else {}
        evidence_item_ids = string_list(profile_row.get("evidence_item_ids"))
        matched_proposals = [proposal_id for proposal_id in active_skill_proposals if proposal_id in evidence_item_ids]
        if not matched_proposals and evidence_item_ids and not active_skill_proposals:
            matched_proposals = evidence_item_ids
        if not matched_proposals:
            continue

        selected_lane = optional_string(profile_row.get("selected_local_lane")) or ""
        route_profile = optional_string(profile_row.get("route_profile")) or "generic_skill_workflow"
        row_diagnostics = string_list(profile_row.get("diagnostics"))
        if selected_lane not in allowed_lane_set:
            row_diagnostics.append("selected_lane_not_bounded")
        if profile_row.get("local_validation_required") is not True:
            row_diagnostics.append("local_validation_not_required")
        if profile_row.get("runtime_action_allowed") is not False:
            row_diagnostics.append("runtime_action_not_denied")
        if profile_row.get("external_skill_activation_allowed") is not False:
            row_diagnostics.append("external_skill_activation_not_denied")
        if profile_row.get("external_harness_execution_allowed") is not False:
            row_diagnostics.append("external_harness_execution_not_denied")
        if profile_row.get("provider_runtime_launch_allowed") is not False:
            row_diagnostics.append("provider_runtime_launch_not_denied")
        if profile_row.get("remote_execution_allowed") is not False:
            row_diagnostics.append("remote_execution_not_denied")

        row_ready = ready and profile_row.get("status") == "ready" and not row_diagnostics
        diagnostics.extend(
            f"{proposal_id}:{diagnostic}"
            for proposal_id in matched_proposals
            for diagnostic in row_diagnostics
        )
        for proposal_id in matched_proposals:
            rows.append(
                {
                    "proposal_id": proposal_id,
                    "route_profile": route_profile,
                    "status": "ready" if row_ready else "blocked",
                    "decision": "proposal_mapped_to_bounded_local_lane"
                    if row_ready
                    else "repair_proposal_lane_before_activation",
                    "selected_local_lane": selected_lane,
                    "allowed_local_lanes": allowed_lanes,
                    "lane_bounded": selected_lane in allowed_lane_set,
                    "validation_gate": optional_string(profile_row.get("validation_gate")) or "",
                    "validation_scope": optional_string(profile_row.get("validation_scope")) or "",
                    "evidence_ref_mode": "selected_item_ids_only",
                    "evidence_item_ids": evidence_item_ids,
                    "candidate_source_hashes": string_list(profile_row.get("candidate_source_hashes")),
                    "candidate_source_count": len(string_list(profile_row.get("candidate_source_hashes"))),
                    "required_validation": string_list(profile_row.get("required_validation")),
                    "provider_runtime_replay_commands": string_list(
                        profile_row.get("provider_runtime_replay_commands")
                    ),
                    "diagnostics": sorted(dict.fromkeys(row_diagnostics)),
                    "local_validation_required": True,
                    "body_free": True,
                    "runtime_action": "none",
                    "runtime_action_allowed": False,
                    "external_skill_activation_allowed": False,
                    "external_skill_code_allowed": False,
                    "external_agent_activation_allowed": False,
                    "external_harness_execution_allowed": False,
                    "provider_runtime_launch_allowed": False,
                    "remote_execution_allowed": False,
                    "raw_evidence_exported": False,
                    "raw_evidence_urls_exported": False,
                    "raw_source_urls_exported": False,
                    "raw_target_paths_exported": False,
                    "raw_upstream_body_exported": False,
                }
            )

    represented_proposals = {str(row.get("proposal_id") or "") for row in rows}
    missing_proposals = [proposal_id for proposal_id in active_skill_proposals if proposal_id not in represented_proposals]
    diagnostics.extend(f"{proposal_id}:proposal_not_mapped_to_profile_lane" for proposal_id in missing_proposals)
    blocked_rows = [row for row in rows if row.get("status") != "ready"]
    contract_ready = (
        ready
        and route_profile_lane_contract.get("status") == "ready"
        and bool(rows)
        and not blocked_rows
        and not missing_proposals
    )

    return {
        "controller_surface": "skill_route_discovery_pass3_proposal_lane_activation_contract",
        "status": "ready" if contract_ready else "blocked",
        "decision": "active_proposals_mapped_to_bounded_local_lanes_before_activation"
        if contract_ready
        else "repair_active_proposal_lane_contract_before_activation",
        "validation_gate": "focused-evidence-review",
        "route_profile_lane_contract_status": optional_string(route_profile_lane_contract.get("status")) or "",
        "proposal_count": len(rows),
        "ready_proposal_count": len(rows) - len(blocked_rows),
        "blocked_proposal_count": len(blocked_rows),
        "active_skill_proposal_ids": active_skill_proposals,
        "blocked_adjacent_proposal_ids": adjacent_proposals,
        "missing_proposal_ids": missing_proposals,
        "allowed_local_lanes": allowed_lanes,
        "selected_local_lanes": sorted(
            {
                str(row.get("selected_local_lane") or "")
                for row in rows
                if row.get("selected_local_lane")
            }
        ),
        "route_profiles": sorted(
            {
                str(row.get("route_profile") or "")
                for row in rows
                if row.get("route_profile")
            }
        ),
        "evidence_ref_mode": "selected_item_ids_only",
        "rows": rows,
        "diagnostics": sorted(dict.fromkeys(diagnostics)),
        "local_validation_required": True,
        "body_free": True,
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_skill_code_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass3_route_profile_lane_contract(
    *,
    ready: bool,
    current_action: dict[str, Any],
    profile_activation_gates: dict[str, Any],
) -> dict[str, Any]:
    """Render pass-3 route profiles as bounded local lanes before activation."""

    from blackhole_agent.skill_routing import SKILL_ROUTE_DISCOVERY_ALLOWED_LANES

    allowed_lanes = list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES)
    allowed_lane_set = set(allowed_lanes)
    gate_rows = profile_activation_gates.get("rows")
    gate_rows = gate_rows if isinstance(gate_rows, list) else []

    rows: list[dict[str, Any]] = []
    diagnostics: list[str] = []
    for raw_gate in gate_rows:
        gate = raw_gate if isinstance(raw_gate, dict) else {}
        route_profile = optional_string(gate.get("route_profile")) or "generic_skill_workflow"
        selected_lanes = [
            lane for lane in string_list(gate.get("selected_local_lanes")) if lane in allowed_lane_set
        ]
        selected_lane = selected_lanes[0] if selected_lanes else ""
        row_diagnostics = string_list(gate.get("activation_blockers"))
        if not selected_lane:
            row_diagnostics.append("bounded_local_lane_missing")
        if gate.get("local_validation_required") is not True:
            row_diagnostics.append("local_validation_not_required")
        if gate.get("runtime_action_allowed") is not False:
            row_diagnostics.append("runtime_action_not_denied")
        if gate.get("external_skill_activation_allowed") is not False:
            row_diagnostics.append("external_skill_activation_not_denied")
        if gate.get("external_harness_execution_allowed") is not False:
            row_diagnostics.append("external_harness_execution_not_denied")
        if gate.get("provider_runtime_launch_allowed") is not False:
            row_diagnostics.append("provider_runtime_launch_not_denied")

        row_ready = ready and not row_diagnostics
        diagnostics.extend(f"{route_profile}:{diagnostic}" for diagnostic in row_diagnostics)
        rows.append(
            {
                "route_profile": route_profile,
                "status": "ready" if row_ready else "blocked",
                "decision": "profile_lane_bounded_for_local_validation"
                if row_ready
                else "repair_profile_lane_contract_before_activation",
                "selected_local_lane": selected_lane,
                "allowed_local_lanes": allowed_lanes,
                "validation_scope": f"local_{selected_lane}_lane_only" if selected_lane else "",
                "validation_gate": optional_string(gate.get("validation_gate")) or "",
                "route_probe_decision": optional_string(gate.get("route_probe_decision"))
                or "skill_route_discovery",
                "required_metadata": string_list(gate.get("required_metadata")),
                "acceptance_contract_ready": gate.get("acceptance_contract_ready") is True,
                "evidence_ref_mode": "selected_item_ids_only",
                "evidence_item_ids": string_list(gate.get("evidence_item_ids")),
                "evidence_item_id_count": len(string_list(gate.get("evidence_item_ids"))),
                "candidate_source_hashes": string_list(gate.get("candidate_source_hashes")),
                "candidate_source_count": len(string_list(gate.get("candidate_source_hashes"))),
                "required_validation": sorted(
                    dict.fromkeys(
                        string_list(gate.get("required_validation"))
                        or string_list(current_action.get("required_validation"))
                    )
                ),
                "provider_runtime_replay_commands": sorted(
                    dict.fromkeys(
                        string_list(gate.get("provider_runtime_replay_commands"))
                        or string_list(current_action.get("provider_runtime_replay_commands"))
                    )
                ),
                "diagnostics": sorted(dict.fromkeys(row_diagnostics)),
                "local_validation_required": True,
                "body_free": True,
                "runtime_action": "none",
                "runtime_action_allowed": False,
                "external_skill_activation_allowed": False,
                "external_skill_code_allowed": False,
                "external_agent_activation_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_target_paths_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    blocked_rows = [row for row in rows if row.get("status") != "ready"]
    contract_ready = (
        ready
        and bool(rows)
        and not blocked_rows
        and profile_activation_gates.get("status") == "ready"
    )
    return {
        "controller_surface": "skill_route_discovery_pass3_route_profile_lane_contract",
        "status": "ready" if contract_ready else "blocked",
        "decision": "route_profiles_mapped_to_bounded_local_lanes_before_final_pass"
        if contract_ready
        else "repair_route_profile_lane_contract_before_final_pass",
        "validation_gate": "focused-evidence-review",
        "profile_activation_gate_status": optional_string(profile_activation_gates.get("status")) or "",
        "profile_count": len(rows),
        "ready_profile_count": len(rows) - len(blocked_rows),
        "blocked_profile_count": len(blocked_rows),
        "blocked_profiles": [str(row.get("route_profile") or "") for row in blocked_rows],
        "allowed_local_lanes": allowed_lanes,
        "selected_local_lanes": sorted(
            {
                str(row.get("selected_local_lane") or "")
                for row in rows
                if row.get("selected_local_lane")
            }
        ),
        "route_profiles": [str(row.get("route_profile") or "") for row in rows],
        "evidence_ref_mode": "selected_item_ids_only",
        "rows": rows,
        "diagnostics": sorted(dict.fromkeys(diagnostics)),
        "required_validation": string_list(current_action.get("required_validation")),
        "provider_runtime_replay_commands": string_list(
            current_action.get("provider_runtime_replay_commands")
        ),
        "local_validation_required": True,
        "body_free": True,
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_skill_code_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass3_adjacent_general_agent_project_eval(
    *,
    raw_input: dict[str, Any],
) -> dict[str, Any]:
    """Expose adjacent general-agent evidence without inheriting skill lanes."""

    window = raw_input.get("capability_window")
    window = window if isinstance(window, dict) else {}
    evidence_urls = string_list(window.get("evidence_urls"))
    anchoring_proposals = string_list(window.get("anchoring_proposals"))
    records = skill_route_discovery_pass3_adjacent_general_agent_records(raw_input)
    general_agent_refs = [
        ref
        for ref in (*evidence_urls, *anchoring_proposals)
        if _skill_route_discovery_is_general_agent_ref(ref)
    ]
    source_url_refs = [ref for ref in evidence_urls if _skill_route_discovery_is_general_agent_ref(ref)]
    source_hashes = sorted({stable_text_hash(ref) for ref in source_url_refs})
    proposal_refs = [ref for ref in anchoring_proposals if _skill_route_discovery_is_general_agent_ref(ref)]
    present = bool(general_agent_refs or records)
    empty_hint_count = sum(1 for record in records if not record["route_hints"])
    eval_required_count = sum(1 for record in records if record["agent_harness_eval_required"])

    return {
        "controller_surface": "skill_route_discovery_pass3_adjacent_general_agent_project_eval",
        "status": "gated" if present else "not_present",
        "decision": (
            "hold_adjacent_general_agent_projects_to_agent_harness_eval"
            if present
            else "no_adjacent_general_agent_project_evidence_detected"
        ),
        "agent_harness_eval_required": present,
        "skill_route_discovery_inherited": False,
        "primary_route": "agent_harness_eval_required" if present else "none",
        "allowed_local_lanes": ["documentation", "test", "code_patch"] if present else [],
        "blocked_skill_route_lanes": ["documentation", "config", "test", "code_patch"] if present else [],
        "source_hashes": source_hashes,
        "source_ref_count": len(source_hashes),
        "proposal_ref_hashes": sorted({stable_text_hash(ref) for ref in proposal_refs}),
        "proposal_ref_count": len(set(proposal_refs)),
        "record_count": len(records),
        "empty_route_hint_record_count": empty_hint_count,
        "agent_harness_eval_required_record_count": eval_required_count,
        "records": records,
        "evidence_ref_mode": "hashes_only",
        "replay_commands": [SKILL_ROUTE_DISCOVERY_PREACTIVATION_HARNESS_COMMAND] if present else [],
        "local_validation_required": present,
        "runtime_action": "none",
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_source_urls_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass3_adjacent_general_agent_records(raw_input: dict[str, Any]) -> list[dict[str, Any]]:
    """Collect body-free adjacent general-agent rows from local fixture inputs."""

    raw_records: list[Any] = []
    for key in ("evidence_items", "candidates", "summaries"):
        value = raw_input.get(key)
        if isinstance(value, list):
            raw_records.extend(value)

    rows: list[dict[str, Any]] = []
    for index, raw_record in enumerate(raw_records, start=1):
        if not isinstance(raw_record, dict):
            continue
        text = " ".join(
            part
            for part in (
                optional_string(raw_record.get("item_id")),
                optional_string(raw_record.get("name")),
                optional_string(raw_record.get("title")),
                optional_string(raw_record.get("summary")),
                optional_string(raw_record.get("evidence_summary")),
                optional_string(raw_record.get("source_url")),
                " ".join(string_list(raw_record.get("topics"))),
            )
            if part
        )
        if not _skill_route_discovery_is_general_agent_ref(text):
            continue
        route_hints = string_list(raw_record.get("route_hints"))
        suggested_lanes = string_list(raw_record.get("suggested_lanes")) or string_list(
            raw_record.get("candidate_lanes")
        )
        allowed_lanes = [
            lane for lane in suggested_lanes if lane in AGENT_HARNESS_EVAL_ALLOWED_LANES
        ] or list(AGENT_HARNESS_EVAL_ALLOWED_LANES)
        source_url = optional_string(raw_record.get("source_url")) or ""
        item_id = optional_string(raw_record.get("item_id")) or optional_string(raw_record.get("name")) or f"record-{index}"
        rows.append(
            {
                "item_id": item_id,
                "source_url_hash": stable_text_hash(source_url) if source_url else None,
                "route_hints": route_hints,
                "route_hints_empty": not route_hints,
                "agent_harness_eval_required": True,
                "skill_route_discovery_inherited": False,
                "allowed_local_lanes": allowed_lanes,
                "blocked_skill_route_lanes": ["documentation", "config", "test", "code_patch"],
                "local_validation_required": True,
                "runtime_action": "none",
                "runtime_action_allowed": False,
                "external_skill_activation_allowed": False,
                "external_agent_activation_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_source_url_exported": False,
                "raw_evidence_body_exported": False,
                "raw_upstream_body_exported": False,
            }
        )
    return rows


def _skill_route_discovery_is_general_agent_ref(value: str) -> bool:
    normalized = value.casefold()
    return any(
        marker in normalized
        for marker in (
            "agent-harness",
            "agent_harness",
            "general-agent",
            "general_agent",
            "omnigent-ai/omnigent",
            "qwen-agentworld",
            "qwenlm/qwen-agentworld",
        )
    )


def skill_route_discovery_pass3_local_validation_probe(
    *,
    ready: bool,
    profile_activation_gates: dict[str, Any],
    profile_validation_proof: dict[str, Any],
    promotion_runbook: dict[str, Any],
) -> dict[str, Any]:
    """Expose one pass-3 probe that maps skill evidence to bounded replay lanes."""

    from blackhole_agent.skill_routing import SKILL_ROUTE_DISCOVERY_ALLOWED_LANES

    gate_rows = profile_activation_gates.get("rows")
    gate_rows = gate_rows if isinstance(gate_rows, list) else []
    proof_rows = profile_validation_proof.get("rows")
    proof_rows = proof_rows if isinstance(proof_rows, list) else []
    runbook_rows = promotion_runbook.get("rows")
    runbook_rows = runbook_rows if isinstance(runbook_rows, list) else []

    proof_by_profile = {
        optional_string(row.get("route_profile")) or "": row
        for row in proof_rows
        if isinstance(row, dict) and optional_string(row.get("route_profile"))
    }
    runbook_by_profile: dict[str, dict[str, Any]] = {}
    for raw_step in runbook_rows:
        step = raw_step if isinstance(raw_step, dict) else {}
        for profile in string_list(step.get("route_profiles")):
            runbook_by_profile.setdefault(profile, step)

    rows: list[dict[str, Any]] = []
    diagnostics: list[str] = []
    for raw_gate in gate_rows:
        gate = raw_gate if isinstance(raw_gate, dict) else {}
        profile = optional_string(gate.get("route_profile")) or ""
        proof = proof_by_profile.get(profile, {})
        runbook_step = runbook_by_profile.get(profile, {})
        selected_lanes = string_list(gate.get("selected_local_lanes"))
        selected_lane = (
            selected_lanes[0]
            if selected_lanes
            else optional_string(proof.get("selected_local_lane")) or ""
        )
        route_probe_decision = optional_string(gate.get("route_probe_decision")) or "skill_route_discovery"
        acceptance_ready = gate.get("acceptance_contract_ready") is True
        proof_ready = proof.get("status") == "ready"
        runbook_ready = runbook_step.get("status") == "ready"
        selected_lane_bounded = selected_lane in SKILL_ROUTE_DISCOVERY_ALLOWED_LANES
        blockers = sorted(
            dict.fromkeys(
                string_list(gate.get("activation_blockers"))
                + string_list(proof.get("blockers"))
                + string_list(runbook_step.get("blockers"))
                + ([] if selected_lane_bounded else ["unbounded_or_missing_local_lane"])
                + ([] if acceptance_ready else ["acceptance_contract_not_ready"])
                + ([] if proof_ready else ["local_artifact_proof_not_ready"])
                + ([] if runbook_ready else ["promotion_runbook_step_not_ready"])
                + (
                    []
                    if profile != "codex_workflow_gate" or route_probe_decision == "skill_route_discovery_first"
                    else ["skill_route_discovery_first_not_confirmed"]
                )
            )
        )
        diagnostics.extend(f"{profile}:{blocker}" for blocker in blockers if profile)
        rows.append(
            {
                "route_profile": profile,
                "status": "ready" if ready and not blockers else "blocked",
                "decision": "validate_local_lane_before_activation"
                if ready and not blockers
                else "repair_local_validation_probe_before_activation",
                "selected_local_lane": selected_lane,
                "validation_scope": f"local_{selected_lane}_lane_only" if selected_lane else "",
                "validation_gate": optional_string(gate.get("validation_gate")) or "",
                "route_probe_decision": route_probe_decision,
                "queue_roles": string_list(gate.get("queue_roles")),
                "queue_fingerprint": optional_string(runbook_step.get("queue_fingerprint")) or "",
                "evidence_ref_mode": "selected_item_ids_only",
                "evidence_item_ids": string_list(gate.get("evidence_item_ids")),
                "evidence_item_id_count": len(string_list(gate.get("evidence_item_ids"))),
                "candidate_source_hashes": string_list(gate.get("candidate_source_hashes")),
                "candidate_source_count": len(string_list(gate.get("candidate_source_hashes"))),
                "required_validation": string_list(gate.get("required_validation")),
                "required_validation_hashes": [
                    stable_text_hash(command) for command in string_list(gate.get("required_validation"))
                ],
                "provider_runtime_replay_commands": string_list(gate.get("provider_runtime_replay_commands")),
                "acceptance_contract_ready": acceptance_ready,
                "local_artifact_proof_present": proof.get("local_artifact_proof_present") is True,
                "promotion_runbook_step_ready": runbook_ready,
                "blockers": blockers,
                "local_validation_required": True,
                "body_free": True,
                "runtime_action": "none",
                "runtime_action_allowed": False,
                "external_skill_activation_allowed": False,
                "external_skill_code_allowed": False,
                "external_agent_activation_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_target_paths_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    blocked_rows = [row for row in rows if row.get("status") != "ready"]
    probe_ready = (
        ready
        and bool(rows)
        and not blocked_rows
        and profile_activation_gates.get("status") == "ready"
        and profile_validation_proof.get("status") == "ready"
        and promotion_runbook.get("status") == "ready"
    )
    return {
        "controller_surface": "skill_route_discovery_pass3_local_validation_probe",
        "status": "ready" if probe_ready else "blocked",
        "decision": "local_validation_probe_ready_for_activation_review"
        if probe_ready
        else "repair_local_validation_probe_before_activation_review",
        "validation_gate": "focused-evidence-review",
        "profile_count": len(rows),
        "ready_profile_count": len(rows) - len(blocked_rows),
        "blocked_profile_count": len(blocked_rows),
        "blocked_profiles": [str(row.get("route_profile") or "") for row in blocked_rows],
        "selected_local_lanes": sorted(
            {
                str(row.get("selected_local_lane") or "")
                for row in rows
                if row.get("selected_local_lane")
            }
        ),
        "allowed_local_lanes": list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES),
        "route_profiles": [str(row.get("route_profile") or "") for row in rows],
        "rows": rows,
        "diagnostics": sorted(dict.fromkeys(diagnostics)),
        "local_validation_required": True,
        "body_free": True,
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_skill_code_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass3_promotion_runbook(
    *,
    ready: bool,
    activation_proof_summary: dict[str, Any],
    operator_checkpoint_list: dict[str, Any],
    profile_validation_proof: dict[str, Any],
) -> dict[str, Any]:
    """Build one ordered supervisor replay gate from pass-3 proof surfaces."""

    from blackhole_agent.skill_routing import SKILL_ROUTE_DISCOVERY_ALLOWED_LANES

    checkpoint_rows = operator_checkpoint_list.get("rows")
    checkpoint_rows = checkpoint_rows if isinstance(checkpoint_rows, list) else []
    proof_rows = profile_validation_proof.get("rows")
    proof_rows = proof_rows if isinstance(proof_rows, list) else []
    activation_rows = activation_proof_summary.get("rows")
    activation_rows = activation_rows if isinstance(activation_rows, list) else []

    proof_by_profile = {
        optional_string(row.get("route_profile")) or "": row
        for row in proof_rows
        if isinstance(row, dict) and optional_string(row.get("route_profile"))
    }
    activation_by_profile = {
        optional_string(row.get("route_profile")) or "": row
        for row in activation_rows
        if isinstance(row, dict) and optional_string(row.get("route_profile"))
    }

    steps: list[dict[str, Any]] = []
    step_blockers: list[str] = []
    for raw_row in checkpoint_rows:
        checkpoint = raw_row if isinstance(raw_row, dict) else {}
        profiles = string_list(checkpoint.get("route_profiles"))
        profile_proofs = [proof_by_profile.get(profile, {}) for profile in profiles]
        profile_summaries = [activation_by_profile.get(profile, {}) for profile in profiles]
        blockers = sorted(
            dict.fromkeys(
                string_list(checkpoint.get("blockers"))
                + [
                    f"{profile}:profile_proof_not_ready"
                    for profile, proof in zip(profiles, profile_proofs, strict=False)
                    if proof.get("status") != "ready"
                ]
                + [
                    f"{profile}:activation_summary_not_ready"
                    for profile, summary in zip(profiles, profile_summaries, strict=False)
                    if summary.get("status") != "ready"
                ]
            )
        )
        step_blockers.extend(blockers)
        required_validation = string_list(checkpoint.get("required_validation"))
        steps.append(
            {
                "step": optional_string(checkpoint.get("checkpoint")) or "",
                "queue_position": int(checkpoint.get("queue_position") or len(steps) + 1),
                "queue_role": optional_string(checkpoint.get("queue_role")) or "",
                "status": "ready" if ready and not blockers else "blocked",
                "selected_local_lane": optional_string(checkpoint.get("selected_local_lane")) or "",
                "route_profiles": profiles,
                "profile_validation_gates": [
                    optional_string(proof.get("validation_gate")) or ""
                    for proof in profile_proofs
                    if optional_string(proof.get("validation_gate"))
                ],
                "evidence_ref_mode": "selected_item_ids_only",
                "evidence_item_id_count": int(checkpoint.get("evidence_item_id_count") or 0),
                "candidate_source_count": int(checkpoint.get("candidate_source_count") or 0),
                "queue_fingerprint": optional_string(checkpoint.get("queue_fingerprint")) or "",
                "required_validation": required_validation,
                "required_validation_hashes": [stable_text_hash(command) for command in required_validation],
                "provider_runtime_replay_commands": string_list(
                    checkpoint.get("provider_runtime_replay_commands")
                ),
                "blockers": blockers,
                "local_validation_required": True,
                "body_free": True,
                "runtime_action_allowed": False,
                "external_skill_activation_allowed": False,
                "external_skill_code_allowed": False,
                "external_agent_activation_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_target_paths_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    promotion_ready = (
        ready
        and operator_checkpoint_list.get("status") == "ready"
        and activation_proof_summary.get("status") == "ready"
        and profile_validation_proof.get("status") == "ready"
        and bool(steps)
        and not step_blockers
    )
    return {
        "controller_surface": "skill_route_discovery_pass3_promotion_runbook",
        "status": "ready" if promotion_ready else "blocked",
        "decision": "supervisor_can_replay_ordered_pass3_runbook"
        if promotion_ready
        else "repair_pass3_promotion_runbook_before_final_pass",
        "validation_gate": "focused-evidence-review",
        "activation_proof_status": optional_string(activation_proof_summary.get("status")) or "",
        "operator_checkpoint_status": optional_string(operator_checkpoint_list.get("status")) or "",
        "profile_validation_proof_status": optional_string(profile_validation_proof.get("status")) or "",
        "step_count": len(steps),
        "ready_step_count": len([step for step in steps if step.get("status") == "ready"]),
        "blocked_step_count": len([step for step in steps if step.get("status") != "ready"]),
        "selected_local_lanes": string_list(activation_proof_summary.get("selected_local_lanes")),
        "allowed_local_lanes": list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES),
        "required_validation_command_hashes": string_list(
            activation_proof_summary.get("required_validation_command_hashes")
        ),
        "rows": steps,
        "diagnostics": sorted(dict.fromkeys(string_list(profile_validation_proof.get("diagnostics")))),
        "blockers": sorted(dict.fromkeys(step_blockers)),
        "local_validation_required": True,
        "body_free": True,
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_skill_code_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass3_control_plane(
    *,
    ready: bool,
    current_action: dict[str, Any],
    pass_validation_replay_queue: dict[str, Any],
    operator_checkpoint_list: dict[str, Any],
    profile_validation_proof: dict[str, Any],
    activation_proof_summary: dict[str, Any],
    promotion_runbook: dict[str, Any],
    diagnostics: list[str],
) -> dict[str, Any]:
    """Expose pass-3 skill-route handoff as a five-stage runner workflow."""

    queue_rows = pass_validation_replay_queue.get("rows")
    queue_rows = queue_rows if isinstance(queue_rows, list) else []
    checkpoint_rows = operator_checkpoint_list.get("rows")
    checkpoint_rows = checkpoint_rows if isinstance(checkpoint_rows, list) else []
    proof_rows = profile_validation_proof.get("rows")
    proof_rows = proof_rows if isinstance(proof_rows, list) else []
    runbook_rows = promotion_runbook.get("rows")
    runbook_rows = runbook_rows if isinstance(runbook_rows, list) else []

    stage_specs = [
        (
            "intake",
            pass_validation_replay_queue.get("status") == "ready" and bool(queue_rows),
            "pass_validation_replay_queue",
        ),
        (
            "midflight",
            current_action.get("status") == "ready"
            and operator_checkpoint_list.get("status") == "ready"
            and bool(checkpoint_rows),
            "current_action_and_operator_checkpoints",
        ),
        (
            "recovery",
            profile_validation_proof.get("status") == "ready" and bool(proof_rows),
            "profile_validation_proof",
        ),
        (
            "replay",
            promotion_runbook.get("status") == "ready" and bool(runbook_rows),
            "promotion_runbook",
        ),
        (
            "report",
            activation_proof_summary.get("status") == "ready",
            "activation_proof_summary",
        ),
    ]
    stages = [
        {
            "stage": stage,
            "status": "ready" if stage_ready else "blocked",
            "artifact": artifact,
            "artifact_hash": stable_text_hash(artifact),
            "operator_visible": True,
            "body_free": True,
            "raw_artifact_paths_exported": False,
        }
        for stage, stage_ready, artifact in stage_specs
    ]
    missing_stages = [stage["stage"] for stage in stages if stage["status"] != "ready"]
    replay_command_hashes = sorted(
        {
            stable_text_hash(command)
            for row in runbook_rows
            for command in string_list(row.get("required_validation"))
        }
    )
    provider_replay_command_hashes = sorted(
        {
            stable_text_hash(command)
            for row in runbook_rows
            for command in string_list(row.get("provider_runtime_replay_commands"))
        }
    )
    workflow_fingerprint = stable_json_hash(
        {
            "current_pass": int(current_action.get("current_pass") or 0),
            "next_pass": int(current_action.get("next_pass") or 0),
            "queue_fingerprints": string_list(pass_validation_replay_queue.get("queue_fingerprints")),
            "activation_rows": [
                {
                    "route_profile": optional_string(row.get("route_profile")) or "",
                    "selected_local_lane": optional_string(row.get("selected_local_lane")) or "",
                    "status": optional_string(row.get("status")) or "",
                }
                for row in activation_proof_summary.get("rows", [])
                if isinstance(row, dict)
            ],
            "stage_statuses": [(stage["stage"], stage["status"]) for stage in stages],
            "diagnostics": sorted(dict.fromkeys(diagnostics)),
        }
    )
    control_ready = ready and not missing_stages and not diagnostics
    return {
        "controller_surface": "skill_route_discovery_pass3_runner_harness_control_plane",
        "status": "ready" if control_ready else "blocked",
        "decision": "pass3_runner_workflow_ready_for_supervisor_replay"
        if control_ready
        else "repair_pass3_runner_workflow_before_replay",
        "stage_order": [stage["stage"] for stage in stages],
        "stage_count": len(stages),
        "ready_stage_count": len(stages) - len(missing_stages),
        "blocked_stage_count": len(missing_stages),
        "missing_stages": missing_stages,
        "stages": stages,
        "workflow_fingerprint": workflow_fingerprint,
        "queue_count": int(pass_validation_replay_queue.get("queue_count") or len(queue_rows)),
        "checkpoint_count": int(operator_checkpoint_list.get("checkpoint_count") or len(checkpoint_rows)),
        "profile_count": int(profile_validation_proof.get("profile_count") or len(proof_rows)),
        "runbook_step_count": int(promotion_runbook.get("step_count") or len(runbook_rows)),
        "report_profile_count": int(activation_proof_summary.get("profile_count") or 0),
        "replay_command_hashes": replay_command_hashes,
        "provider_runtime_replay_command_hashes": provider_replay_command_hashes,
        "diagnostics": sorted(dict.fromkeys(diagnostics)),
        "local_validation_required": True,
        "body_free": True,
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_skill_code_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
        "raw_artifact_paths_exported": False,
    }


def skill_route_discovery_pass3_activation_proof_summary(
    *,
    ready: bool,
    profile_validation_proof: dict[str, Any],
) -> dict[str, Any]:
    """Collapse pass-3 profile proof into a promotion-facing decision summary."""

    from blackhole_agent.skill_routing import SKILL_ROUTE_DISCOVERY_ALLOWED_LANES

    proof_rows = profile_validation_proof.get("rows")
    proof_rows = proof_rows if isinstance(proof_rows, list) else []
    rows: list[dict[str, Any]] = []
    required_validation_hashes: list[str] = []
    blocked_profiles: list[str] = []
    for raw_row in proof_rows:
        row = raw_row if isinstance(raw_row, dict) else {}
        profile = optional_string(row.get("route_profile")) or ""
        blockers = string_list(row.get("blockers"))
        required_validation = string_list(row.get("required_validation"))
        required_validation_hashes.extend(stable_text_hash(command) for command in required_validation)
        proof_blocked = bool(blockers)
        if proof_blocked and profile:
            blocked_profiles.append(profile)
        rows.append(
            {
                "route_profile": profile,
                "status": "blocked" if proof_blocked else "ready",
                "selected_local_lane": optional_string(row.get("selected_local_lane")) or "",
                "validation_gate": optional_string(row.get("validation_gate")) or "",
                "local_artifact_proof_present": row.get("local_artifact_proof_present") is True,
                "acceptance_contract_ready": row.get("acceptance_contract_ready") is True,
                "evidence_ref_mode": "selected_item_ids_only",
                "evidence_item_id_count": len(string_list(row.get("evidence_item_ids"))),
                "candidate_source_hash_count": len(string_list(row.get("candidate_source_hashes"))),
                "required_validation_count": len(required_validation),
                "blocker_count": len(blockers),
                "blockers": sorted(dict.fromkeys(blockers)),
                "local_validation_required": True,
                "runtime_action": "none",
                "runtime_action_allowed": False,
                "external_skill_activation_allowed": False,
                "external_skill_code_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_target_paths_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    proof_ready = ready and profile_validation_proof.get("status") == "ready" and bool(rows) and not blocked_profiles
    selected_lanes = sorted(
        {
            str(row.get("selected_local_lane") or "")
            for row in rows
            if str(row.get("selected_local_lane") or "") in SKILL_ROUTE_DISCOVERY_ALLOWED_LANES
        }
    )
    return {
        "controller_surface": "skill_route_discovery_pass3_activation_proof_summary",
        "status": "ready" if proof_ready else "blocked",
        "decision": "operator_can_promote_after_focused_replay"
        if proof_ready
        else "repair_profile_validation_proof_before_promotion",
        "validation_gate": "focused-evidence-review",
        "profile_count": len(rows),
        "ready_profile_count": len(rows) - len(blocked_profiles),
        "blocked_profile_count": len(blocked_profiles),
        "blocked_profiles": sorted(dict.fromkeys(blocked_profiles)),
        "selected_local_lanes": selected_lanes,
        "allowed_local_lanes": list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES),
        "required_validation_command_count": len(set(required_validation_hashes)),
        "required_validation_command_hashes": sorted(dict.fromkeys(required_validation_hashes)),
        "local_artifact_proof_lanes": string_list(profile_validation_proof.get("local_artifact_proof_lanes")),
        "rows": rows,
        "diagnostics": string_list(profile_validation_proof.get("diagnostics")),
        "local_validation_required": True,
        "body_free": True,
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_skill_code_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass3_profile_validation_proof(
    *,
    ready: bool,
    raw_input: dict[str, Any],
    rows: list[dict[str, Any]],
    profile_activation_gates: dict[str, Any],
    diagnostics: list[str],
) -> dict[str, Any]:
    """Prove each pass-3 route profile has a bounded local lane before activation."""

    from blackhole_agent.skill_routing import SKILL_ROUTE_DISCOVERY_ALLOWED_LANES

    local_artifact_proofs = raw_input.get("local_artifact_proofs")
    local_artifact_proofs = local_artifact_proofs if isinstance(local_artifact_proofs, list) else []
    proof_lanes = {
        str(proof.get("proposal_kind") or "")
        for proof in local_artifact_proofs
        if isinstance(proof, dict)
    }
    gate_rows = profile_activation_gates.get("rows")
    gate_rows = gate_rows if isinstance(gate_rows, list) else []
    gate_by_profile = {
        str(row.get("route_profile") or ""): row
        for row in gate_rows
        if isinstance(row, dict) and str(row.get("route_profile") or "").strip()
    }
    source_rows: dict[str, dict[str, Any]] = {}
    for row in rows:
        selected_lane = optional_string(row.get("selected_local_lane")) or ""
        for profile in string_list(row.get("route_profiles")):
            entry = source_rows.setdefault(
                profile,
                {
                    "route_profile": profile,
                    "selected_local_lanes": [],
                    "queue_roles": [],
                    "evidence_item_ids": [],
                    "candidate_source_hashes": [],
                    "required_validation": [],
                    "provider_runtime_replay_commands": [],
                },
            )
            if selected_lane:
                entry["selected_local_lanes"].append(selected_lane)
            entry["queue_roles"].append(optional_string(row.get("queue_role")) or "queued_bounded_lane")
            entry["evidence_item_ids"].extend(string_list(row.get("evidence_item_ids")))
            entry["candidate_source_hashes"].extend(string_list(row.get("candidate_source_hashes")))
            entry["required_validation"].extend(string_list(row.get("replay_commands")))
            entry["provider_runtime_replay_commands"].extend(
                string_list(row.get("provider_runtime_replay_commands"))
            )

    proof_rows: list[dict[str, Any]] = []
    proof_diagnostics = list(diagnostics)
    allowed_lanes = set(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES)
    for profile in sorted(set(source_rows) | set(gate_by_profile)):
        source_row = source_rows.get(profile, {})
        gate_row = gate_by_profile.get(profile, {})
        selected_lanes = sorted(dict.fromkeys(string_list(source_row.get("selected_local_lanes"))))
        lane = selected_lanes[0] if len(selected_lanes) == 1 else ""
        row_blockers: list[str] = []
        if not lane or lane not in allowed_lanes:
            row_blockers.append("missing_bounded_selected_lane")
        if lane and lane not in proof_lanes:
            row_blockers.append("missing_local_artifact_proof_for_lane")
        if not string_list(source_row.get("evidence_item_ids")):
            row_blockers.append("missing_selected_item_ids")
        if not string_list(source_row.get("candidate_source_hashes")):
            row_blockers.append("missing_candidate_source_hashes")
        if gate_row.get("acceptance_contract_ready") is not True:
            row_blockers.append("profile_acceptance_contract_not_ready")
        if not string_list(source_row.get("required_validation")):
            row_blockers.append("missing_required_validation")

        proof_diagnostics.extend(f"{profile}:{blocker}" for blocker in row_blockers)
        proof_rows.append(
            {
                "route_profile": profile,
                "status": "ready" if ready and not row_blockers else "blocked",
                "decision": "profile_has_bounded_local_validation_proof"
                if ready and not row_blockers
                else "repair_profile_validation_proof_before_activation",
                "selected_local_lane": lane,
                "queue_roles": sorted(dict.fromkeys(string_list(source_row.get("queue_roles")))),
                "validation_gate": optional_string(gate_row.get("validation_gate")) or "",
                "evidence_ref_mode": "selected_item_ids_only",
                "evidence_item_ids": sorted(dict.fromkeys(string_list(source_row.get("evidence_item_ids")))),
                "candidate_source_hashes": sorted(
                    dict.fromkeys(string_list(source_row.get("candidate_source_hashes")))
                ),
                "local_artifact_proof_present": bool(lane and lane in proof_lanes),
                "required_validation": sorted(
                    dict.fromkeys(string_list(source_row.get("required_validation")))
                ),
                "provider_runtime_replay_commands": sorted(
                    dict.fromkeys(string_list(source_row.get("provider_runtime_replay_commands")))
                ),
                "acceptance_contract_ready": gate_row.get("acceptance_contract_ready") is True,
                "blockers": sorted(dict.fromkeys(row_blockers)),
                "local_validation_required": True,
                "runtime_action": "none",
                "runtime_action_allowed": False,
                "external_skill_activation_allowed": False,
                "external_skill_code_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_target_paths_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    blocked_rows = [row["route_profile"] for row in proof_rows if row["status"] != "ready"]
    proof_ready = bool(proof_rows) and ready and not blocked_rows
    return {
        "controller_surface": "skill_route_discovery_pass3_profile_validation_proof",
        "status": "ready" if proof_ready else "blocked",
        "decision": "profiles_have_bounded_local_validation_proof"
        if proof_ready
        else "repair_profile_validation_proof_before_final_activation",
        "validation_gate": "focused-evidence-review",
        "profile_count": len(proof_rows),
        "ready_profile_count": len(proof_rows) - len(blocked_rows),
        "blocked_profile_count": len(blocked_rows),
        "blocked_profiles": blocked_rows,
        "allowed_local_lanes": list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES),
        "local_artifact_proof_lanes": sorted(lane for lane in proof_lanes if lane in allowed_lanes),
        "rows": proof_rows,
        "diagnostics": sorted(dict.fromkeys(proof_diagnostics)),
        "local_validation_required": True,
        "body_free": True,
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_skill_code_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass3_profile_activation_gates(
    *,
    ready: bool,
    rows: list[dict[str, Any]],
    mixed_probe_primary_route: str,
    mixed_probe_secondary_status: str,
    profile_lane_acceptance_contract: dict[str, Any],
    diagnostics: list[str],
) -> dict[str, Any]:
    """Map pass-3 route profiles to bounded local lanes before final activation."""

    from blackhole_agent.skill_routing import SKILL_ROUTE_DISCOVERY_ALLOWED_LANES

    allowed_lanes = list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES)
    contract_rows = profile_lane_acceptance_contract.get("rows")
    contract_rows = contract_rows if isinstance(contract_rows, list) else []
    contract_by_profile = {
        str(row.get("route_profile") or ""): row
        for row in contract_rows
        if isinstance(row, dict) and str(row.get("route_profile") or "").strip()
    }
    profile_contract_status = optional_string(profile_lane_acceptance_contract.get("status")) or ""
    profile_rows: dict[str, dict[str, Any]] = {
        profile: {
            "route_profile": profile,
            "selected_local_lanes": [],
            "queue_roles": [],
            "evidence_item_ids": [],
            "candidate_source_hashes": [],
            "required_validation": [],
            "provider_runtime_replay_commands": [],
        }
        for profile in contract_by_profile
    }
    for row in rows:
        selected_lane = optional_string(row.get("selected_local_lane")) or ""
        queue_role = optional_string(row.get("queue_role")) or "queued_bounded_lane"
        for profile in string_list(row.get("route_profiles")):
            entry = profile_rows.setdefault(
                profile,
                {
                    "route_profile": profile,
                    "selected_local_lanes": [],
                    "queue_roles": [],
                    "evidence_item_ids": [],
                    "candidate_source_hashes": [],
                    "required_validation": [],
                    "provider_runtime_replay_commands": [],
                },
            )
            if selected_lane:
                entry["selected_local_lanes"].append(selected_lane)
            entry["queue_roles"].append(queue_role)
            entry["evidence_item_ids"].extend(string_list(row.get("evidence_item_ids")))
            entry["candidate_source_hashes"].extend(string_list(row.get("candidate_source_hashes")))
            entry["required_validation"].extend(string_list(row.get("replay_commands")))
            entry["provider_runtime_replay_commands"].extend(
                string_list(row.get("provider_runtime_replay_commands"))
            )

    activation_blockers = sorted(dict.fromkeys(diagnostics))
    profile_gate_rows: list[dict[str, Any]] = []
    for profile in sorted(profile_rows):
        entry = profile_rows[profile]
        selected_lanes = sorted(dict.fromkeys(string_list(entry.get("selected_local_lanes"))))
        route_probe_decision = (
            "skill_route_discovery_first"
            if (
                profile == "codex_workflow_gate"
                and mixed_probe_primary_route == "skill_route_discovery"
                and mixed_probe_secondary_status == "blocked_until_local_corroboration"
            )
            else "skill_route_discovery"
        )
        row_blockers = list(activation_blockers)
        if not selected_lanes or set(selected_lanes) - set(allowed_lanes):
            row_blockers.append("unbounded_or_missing_local_lane")
        if profile == "codex_workflow_gate" and route_probe_decision != "skill_route_discovery_first":
            row_blockers.append("skill_route_discovery_first_not_confirmed")
        contract_row = contract_by_profile.get(profile, {})
        contract_status = optional_string(contract_row.get("status")) or "missing"
        acceptance_gates = contract_row.get("acceptance_gates")
        acceptance_gates = acceptance_gates if isinstance(acceptance_gates, dict) else {}
        failed_acceptance_gates = sorted(
            str(gate)
            for gate, passed in acceptance_gates.items()
            if passed is not True
        )
        if profile_contract_status != "ready" or contract_status != "ready":
            row_blockers.append("profile_lane_acceptance_contract_not_ready")
        row_blockers.extend(f"profile_acceptance_gate_failed:{gate}" for gate in failed_acceptance_gates)

        profile_gate_rows.append(
            {
                "route_profile": profile,
                "status": "ready" if ready and not row_blockers else "blocked",
                "decision": "validate_bounded_local_lane_before_activation"
                if ready and not row_blockers
                else "repair_profile_activation_gate_before_final_pass",
                "route_probe_decision": route_probe_decision,
                "validation_gate": optional_string(contract_row.get("validation_gate")) or "",
                "blocked_activation_reason": optional_string(contract_row.get("blocked_activation_reason")) or "",
                "allowed_local_lanes": allowed_lanes,
                "selected_local_lanes": selected_lanes,
                "selected_first_local_lane": optional_string(contract_row.get("selected_first_local_lane")) or "",
                "required_metadata": string_list(contract_row.get("required_metadata")),
                "acceptance_gates": acceptance_gates,
                "acceptance_contract_status": contract_status,
                "acceptance_contract_ready": contract_status == "ready" and not failed_acceptance_gates,
                "queue_roles": sorted(dict.fromkeys(string_list(entry.get("queue_roles")))),
                "evidence_ref_mode": "selected_item_ids_only",
                "evidence_item_ids": sorted(dict.fromkeys(string_list(entry.get("evidence_item_ids")))),
                "candidate_source_hashes": sorted(
                    dict.fromkeys(string_list(entry.get("candidate_source_hashes")))
                ),
                "required_validation": sorted(dict.fromkeys(string_list(entry.get("required_validation")))),
                "provider_runtime_replay_commands": sorted(
                    dict.fromkeys(string_list(entry.get("provider_runtime_replay_commands")))
                ),
                "activation_blockers": sorted(dict.fromkeys(row_blockers)),
                "local_validation_required": True,
                "runtime_action_allowed": False,
                "external_skill_activation_allowed": False,
                "external_skill_code_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_target_paths_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    blocked_profiles = [row["route_profile"] for row in profile_gate_rows if row["status"] != "ready"]
    return {
        "controller_surface": "skill_route_discovery_pass3_profile_activation_gates",
        "status": "ready" if profile_gate_rows and not blocked_profiles else "blocked",
        "decision": "profile_lanes_ready_for_final_pass_validation"
        if profile_gate_rows and not blocked_profiles
        else "repair_profile_lanes_before_final_pass_validation",
        "profile_count": len(profile_gate_rows),
        "ready_profile_count": len(profile_gate_rows) - len(blocked_profiles),
        "blocked_profile_count": len(blocked_profiles),
        "blocked_profiles": blocked_profiles,
        "acceptance_contract_status": profile_contract_status,
        "acceptance_contract_ready": profile_contract_status == "ready",
        "allowed_local_lanes": allowed_lanes,
        "route_profiles": [row["route_profile"] for row in profile_gate_rows],
        "rows": profile_gate_rows,
        "diagnostics": sorted(dict.fromkeys(diagnostics)),
        "local_validation_required": True,
        "body_free": True,
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_skill_code_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass3_final_pass_replay_checklist(
    *,
    ready: bool,
    current_action: dict[str, Any],
    selected_rows: list[dict[str, Any]],
    queued_rows: list[dict[str, Any]],
    mixed_probe_primary_route: str,
    mixed_probe_secondary_status: str,
    diagnostics: list[str],
) -> dict[str, Any]:
    """Return the pass-4 replay checklist without adding activation authority."""

    steps = [
        {
            "step": "replay_selected_current_pass_lane",
            "status": "ready" if selected_rows else "blocked",
            "selected_local_lanes": sorted({row["selected_local_lane"] for row in selected_rows}),
            "route_profiles": sorted(
                {
                    profile
                    for row in selected_rows
                    for profile in string_list(row.get("route_profiles"))
                }
            ),
            "evidence_ref_mode": "selected_item_ids_only",
            "evidence_item_id_count": len(
                {
                    item_id
                    for row in selected_rows
                    for item_id in string_list(row.get("evidence_item_ids"))
                }
            ),
            "required_validation": string_list(current_action.get("required_validation")),
            "runtime_action_allowed": False,
            "external_skill_activation_allowed": False,
            "external_harness_execution_allowed": False,
        },
        {
            "step": "carry_queued_bounded_lanes",
            "status": "ready" if queued_rows else "not_applicable",
            "queued_local_lanes": sorted({row["selected_local_lane"] for row in queued_rows}),
            "route_profiles": sorted(
                {
                    profile
                    for row in queued_rows
                    for profile in string_list(row.get("route_profiles"))
                }
            ),
            "evidence_ref_mode": "selected_item_ids_only",
            "evidence_item_id_count": len(
                {
                    item_id
                    for row in queued_rows
                    for item_id in string_list(row.get("evidence_item_ids"))
                }
            ),
            "runtime_action_allowed": False,
            "external_skill_activation_allowed": False,
            "external_harness_execution_allowed": False,
        },
        {
            "step": "preserve_secondary_harness_block",
            "status": "ready"
            if (
                mixed_probe_primary_route == "skill_route_discovery"
                and mixed_probe_secondary_status == "blocked_until_local_corroboration"
            )
            else "blocked",
            "primary_route": mixed_probe_primary_route,
            "secondary_lane_status": mixed_probe_secondary_status,
            "secondary_harness_eval_allowed": False,
            "secondary_harness_eval_allowed_after": "local_corroboration_or_general_agent_project_claim",
            "runtime_action_allowed": False,
            "external_agent_activation_allowed": False,
            "external_harness_execution_allowed": False,
        },
        {
            "step": "verify_body_free_final_handoff",
            "status": "ready" if not diagnostics else "blocked",
            "diagnostics": sorted(dict.fromkeys(diagnostics)),
            "raw_evidence_exported": False,
            "raw_evidence_urls_exported": False,
            "raw_source_urls_exported": False,
            "raw_target_paths_exported": False,
            "raw_upstream_body_exported": False,
        },
    ]
    return {
        "controller_surface": "skill_route_discovery_pass3_final_pass_replay_checklist",
        "status": "ready" if ready else "blocked",
        "decision": "ready_for_final_pass_replay" if ready else "repair_before_final_pass_replay",
        "step_count": len(steps),
        "steps": steps,
        "required_validation": string_list(current_action.get("required_validation")),
        "provider_runtime_replay_commands": string_list(current_action.get("provider_runtime_replay_commands")),
        "local_validation_required": True,
        "body_free": True,
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_skill_code_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass1_handoff_packet(
    *,
    raw_input: dict[str, Any],
    current_action: dict[str, Any],
    pass_validation_replay_queue: dict[str, Any],
) -> dict[str, Any]:
    """Expose pass-1 continuation work without promoting external projects."""

    from blackhole_agent.skill_routing import SKILL_ROUTE_DISCOVERY_ALLOWED_LANES

    window = raw_input.get("capability_window")
    window = window if isinstance(window, dict) else {}
    evidence_urls = string_list(window.get("evidence_urls"))
    anchoring_proposals = string_list(window.get("anchoring_proposals"))
    current_pass = int(current_action.get("current_pass") or 0)
    selected_lane = optional_string(current_action.get("selected_local_lane")) or "none"
    queued_lanes = string_list(current_action.get("queued_local_lanes"))
    queue_rows = pass_validation_replay_queue.get("rows")
    queue_rows = queue_rows if isinstance(queue_rows, list) else []
    allowed_lanes = set(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES)
    bounded_lanes = sorted(
        {
            lane
            for lane in [selected_lane, *queued_lanes]
            if lane in allowed_lanes
        }
    )
    evidence_item_ids = sorted(
        {
            item_id
            for row in queue_rows
            if isinstance(row, dict)
            for item_id in string_list(row.get("evidence_item_ids"))
        }
    )
    candidate_source_hashes = sorted(
        {
            source_hash
            for row in queue_rows
            if isinstance(row, dict)
            for source_hash in string_list(row.get("candidate_source_hashes"))
        }
    )
    general_agent_evidence_present = any(
        _skill_route_discovery_is_general_agent_ref(ref)
        for ref in [*evidence_urls, *anchoring_proposals]
    )
    ready = (
        current_pass == 1
        and current_action.get("status") == "ready"
        and pass_validation_replay_queue.get("status") == "ready"
        and bool(bounded_lanes)
    )

    return {
        "controller_surface": "skill_route_discovery_pass1_handoff_packet",
        "status": "ready" if ready else "not_applicable" if current_pass != 1 else "blocked",
        "decision": "continue_bounded_skill_route_lane_before_secondary_agent_harness_eval"
        if ready
        else "pass1_handoff_not_currently_ready",
        "theme": optional_string(window.get("theme")) or "skill-route-discovery",
        "capability_slice": optional_string(window.get("capability_slice")) or "",
        "current_pass": current_pass,
        "next_pass": int(current_action.get("next_pass") or 0),
        "total_passes": int(current_action.get("total_passes") or 0),
        "selected_local_lane": selected_lane,
        "queued_local_lanes": queued_lanes,
        "bounded_local_lanes": bounded_lanes,
        "queue_count": int(pass_validation_replay_queue.get("queue_count") or 0),
        "evidence_ref_mode": "selected_item_ids_only",
        "evidence_item_ids": evidence_item_ids,
        "evidence_item_id_count": len(evidence_item_ids),
        "candidate_source_hashes": candidate_source_hashes,
        "candidate_source_count": len(candidate_source_hashes),
        "replay_commands": string_list(current_action.get("required_validation")),
        "provider_runtime_replay_commands": string_list(
            current_action.get("provider_runtime_replay_commands")
        ),
        "adjacent_general_agent_project_eval": {
            "status": "gated" if general_agent_evidence_present else "not_present",
            "agent_harness_eval_required": general_agent_evidence_present,
            "skill_route_discovery_inherited": False,
            "allowed_local_lanes": ["documentation", "test", "code_patch"]
            if general_agent_evidence_present
            else [],
            "replay_commands": [SKILL_ROUTE_DISCOVERY_PREACTIVATION_HARNESS_COMMAND]
            if general_agent_evidence_present
            else [],
            "runtime_action": "none",
            "external_agent_activation_allowed": False,
            "external_harness_execution_allowed": False,
            "raw_source_urls_exported": False,
            "raw_upstream_body_exported": False,
        },
        "local_validation_required": True,
        "body_free": True,
        "runtime_action": "none",
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_skill_code_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass1_validation_queue(
    *,
    raw_input: dict[str, Any],
    pass_validation_replay_queue: dict[str, Any],
    mixed_local_lane_probe: dict[str, Any],
    profile_lane_acceptance_contract: dict[str, Any],
) -> dict[str, Any]:
    """Map pass-1 anchoring proposals to bounded local replay rows."""

    from blackhole_agent.skill_routing import SKILL_ROUTE_DISCOVERY_ALLOWED_LANES

    window = raw_input.get("capability_window")
    window = window if isinstance(window, dict) else {}
    current_pass = int(window.get("current_pass") or window.get("planned_pass") or 0)
    anchoring_proposals = string_list(window.get("anchoring_proposals"))
    queue_rows = pass_validation_replay_queue.get("rows")
    queue_rows = queue_rows if isinstance(queue_rows, list) else []
    allowed_lanes = set(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES)
    profile_contract_rows = profile_lane_acceptance_contract.get("rows")
    profile_contract_rows = profile_contract_rows if isinstance(profile_contract_rows, list) else []
    profile_contract_by_name = {
        optional_string(row.get("route_profile")) or "generic_skill_workflow": row
        for row in profile_contract_rows
        if isinstance(row, dict)
    }

    rows_by_evidence_id: dict[str, dict[str, Any]] = {}
    for row in queue_rows:
        if not isinstance(row, dict):
            continue
        for item_id in string_list(row.get("evidence_item_ids")):
            rows_by_evidence_id[item_id] = row

    rows: list[dict[str, Any]] = []
    diagnostics: list[str] = []
    for proposal_id in anchoring_proposals:
        proposal_lower = proposal_id.casefold()
        if _skill_route_discovery_is_general_agent_ref(proposal_lower):
            rows.append(
                {
                    "proposal_id": proposal_id,
                    "route": "agent_harness_eval_required",
                    "queue_status": "gated",
                    "selected_local_lane": "none",
                    "allowed_local_lanes": ["documentation", "test", "code_patch"],
                    "route_profiles": [],
                    "evidence_ref_mode": "selected_item_ids_only",
                    "evidence_item_ids": [],
                    "evidence_item_id_count": 0,
                    "secondary_lane": "agent_harness_eval_after_local_corroboration",
                    "secondary_lane_status": "blocked_until_local_corroboration",
                    "skill_route_discovery_inherited": False,
                    "ready_for_local_replay": False,
                    "replay_commands": [SKILL_ROUTE_DISCOVERY_PREACTIVATION_HARNESS_COMMAND],
                    "local_validation_required": True,
                    "runtime_action": "none",
                    "external_skill_activation_allowed": False,
                    "external_agent_activation_allowed": False,
                    "external_harness_execution_allowed": False,
                    "provider_runtime_launch_allowed": False,
                    "remote_execution_allowed": False,
                    "raw_evidence_exported": False,
                    "raw_evidence_urls_exported": False,
                    "raw_source_urls_exported": False,
                    "raw_target_paths_exported": False,
                    "raw_upstream_body_exported": False,
                }
            )
            continue

        replay_row = rows_by_evidence_id.get(proposal_id)
        if not replay_row:
            diagnostics.append(f"{stable_text_hash(proposal_id)}:anchoring_proposal_not_in_replay_queue")
            rows.append(
                {
                    "proposal_id": proposal_id,
                    "route": "skill_route_discovery",
                    "queue_status": "blocked",
                    "selected_local_lane": "none",
                    "allowed_local_lanes": list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES),
                    "route_profiles": [],
                    "evidence_ref_mode": "selected_item_ids_only",
                    "evidence_item_ids": [proposal_id],
                    "evidence_item_id_count": 1,
                    "ready_for_local_replay": False,
                    "diagnostics": ["anchoring_proposal_not_in_replay_queue"],
                    "replay_commands": [SKILL_ROUTE_DISCOVERY_VALIDATION_COMMAND],
                    "local_validation_required": True,
                    "runtime_action": "none",
                    "external_skill_activation_allowed": False,
                    "external_agent_activation_allowed": False,
                    "external_harness_execution_allowed": False,
                    "provider_runtime_launch_allowed": False,
                    "remote_execution_allowed": False,
                    "raw_evidence_exported": False,
                    "raw_evidence_urls_exported": False,
                    "raw_source_urls_exported": False,
                    "raw_target_paths_exported": False,
                    "raw_upstream_body_exported": False,
                }
            )
            continue

        selected_lane = optional_string(replay_row.get("selected_local_lane")) or "none"
        row_diagnostics = string_list(replay_row.get("diagnostics"))
        if selected_lane not in allowed_lanes:
            row_diagnostics.append("selected_local_lane_not_bounded")
        if replay_row.get("local_validation_required") is not True:
            row_diagnostics.append("local_validation_not_required")
        if str(replay_row.get("runtime_action") or "none") != "none":
            row_diagnostics.append("runtime_action_requested")
        if replay_row.get("external_skill_activation_allowed") is not False:
            row_diagnostics.append("external_skill_activation_not_denied")
        if row_diagnostics:
            diagnostics.extend(f"{stable_text_hash(proposal_id)}:{diagnostic}" for diagnostic in row_diagnostics)

        route_profiles = skill_route_discovery_pass1_profiles_for_proposal(
            proposal_id,
            string_list(replay_row.get("route_profiles")),
        )
        profile_contracts = [
            skill_route_discovery_pass1_profile_contract_row(
                proposal_id=proposal_id,
                selected_local_lane=selected_lane,
                contract_row=profile_contract_by_name[profile],
            )
            for profile in route_profiles
            if profile in profile_contract_by_name
        ]
        rows.append(
            {
                "proposal_id": proposal_id,
                "route": "skill_route_discovery",
                "queue_status": "ready" if not row_diagnostics else "blocked",
                "selected_local_lane": selected_lane,
                "allowed_local_lanes": list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES),
                "route_profiles": route_profiles,
                "evidence_ref_mode": "selected_item_ids_only",
                "evidence_item_ids": [proposal_id],
                "evidence_item_id_count": 1,
                "candidate_source_hashes": string_list(replay_row.get("candidate_source_hashes")),
                "candidate_source_count": len(string_list(replay_row.get("candidate_source_hashes"))),
                "profile_contracts": profile_contracts,
                "profile_contract_count": len(profile_contracts),
                "ready_for_local_replay": not row_diagnostics,
                "diagnostics": sorted(dict.fromkeys(row_diagnostics)),
                "replay_commands": string_list(replay_row.get("replay_commands")),
                "provider_runtime_replay_commands": string_list(
                    replay_row.get("provider_runtime_replay_commands")
                ),
                "local_validation_required": True,
                "runtime_action": "none",
                "external_skill_activation_allowed": False,
                "external_agent_activation_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_target_paths_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    skill_rows = [row for row in rows if row["route"] == "skill_route_discovery"]
    adjacent_rows = [row for row in rows if row["route"] == "agent_harness_eval_required"]
    mixed_probe_status = optional_string(mixed_local_lane_probe.get("secondary_lane_status")) or ""
    profile_contract_rows = [
        contract
        for row in skill_rows
        for contract in (row.get("profile_contracts") if isinstance(row.get("profile_contracts"), list) else [])
        if isinstance(contract, dict)
    ]
    ready_profile_contract_count = sum(1 for row in profile_contract_rows if row.get("status") == "ready")
    profile_validation_lanes: list[dict[str, Any]] = []
    for contract in profile_contract_rows:
        profile = optional_string(contract.get("route_profile")) or "generic_skill_workflow"
        proposal_ids = sorted(
            {
                row["proposal_id"]
                for row in skill_rows
                if profile in string_list(row.get("route_profiles"))
            }
        )
        replay_commands = sorted(
            {
                command
                for row in skill_rows
                if profile in string_list(row.get("route_profiles"))
                for command in string_list(row.get("replay_commands"))
            }
        )
        provider_runtime_replay_commands = sorted(
            {
                command
                for row in skill_rows
                if profile in string_list(row.get("route_profiles"))
                for command in string_list(row.get("provider_runtime_replay_commands"))
            }
        )
        acceptance_gates = contract.get("acceptance_gates")
        acceptance_gates = acceptance_gates if isinstance(acceptance_gates, dict) else {}
        first_route_required = profile == "codex_workflow_gate"
        profile_validation_lanes.append(
            {
                "route_profile": profile,
                "queue_status": "ready" if contract.get("status") == "ready" else "blocked",
                "selected_local_lane": optional_string(contract.get("selected_first_local_lane")) or "none",
                "validation_gate": optional_string(contract.get("validation_gate")) or "",
                "validation_scope": optional_string(contract.get("validation_scope")) or "",
                "proposal_ids": proposal_ids,
                "proposal_count": len(proposal_ids),
                "required_metadata": string_list(contract.get("required_metadata")),
                "replay_commands": replay_commands,
                "provider_runtime_replay_commands": provider_runtime_replay_commands,
                "first_route_required": first_route_required,
                "first_route_confirmed": acceptance_gates.get("first_route_confirmed") is True,
                "local_validation_required": True,
                "runtime_action": "none",
                "external_skill_activation_allowed": False,
                "external_agent_activation_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_target_paths_exported": False,
                "raw_upstream_body_exported": False,
            }
        )
    ready = (
        current_pass == 1
        and bool(skill_rows)
        and all(row["ready_for_local_replay"] for row in skill_rows)
        and all(row["skill_route_discovery_inherited"] is False for row in adjacent_rows)
        and not diagnostics
    )
    pass1_replay_lane_plan = skill_route_discovery_pass1_replay_lane_plan(
        current_pass=current_pass,
        total_passes=int(window.get("total_passes") or 0),
        ready=ready,
        pass_validation_replay_queue=pass_validation_replay_queue,
        profile_validation_lanes=profile_validation_lanes,
    )
    return {
        "controller_surface": "skill_route_discovery_pass1_validation_queue",
        "status": "ready" if ready else "not_applicable" if current_pass != 1 else "blocked",
        "decision": "pass1_skill_route_validation_queue_ready"
        if ready
        else "repair_pass1_validation_queue_before_replay",
        "current_pass": current_pass,
        "total_passes": int(window.get("total_passes") or 0),
        "anchoring_proposal_count": len(anchoring_proposals),
        "skill_route_row_count": len(skill_rows),
        "adjacent_general_agent_row_count": len(adjacent_rows),
        "ready_skill_route_row_count": sum(1 for row in skill_rows if row["ready_for_local_replay"]),
        "selected_local_lanes": sorted(
            {row["selected_local_lane"] for row in skill_rows if row["selected_local_lane"] in allowed_lanes}
        ),
        "route_profiles": sorted(
            {
                profile
                for row in skill_rows
                for profile in string_list(row.get("route_profiles"))
            }
        ),
        "profile_contract_count": len(profile_contract_rows),
        "ready_profile_contract_count": ready_profile_contract_count,
        "profile_contract_status": "ready"
        if profile_contract_rows and ready_profile_contract_count == len(profile_contract_rows)
        else "blocked",
        "profile_validation_lane_count": len(profile_validation_lanes),
        "ready_profile_validation_lane_count": sum(
            1 for row in profile_validation_lanes if row["queue_status"] == "ready"
        ),
        "profile_validation_lanes": profile_validation_lanes,
        "pass1_replay_lane_plan": pass1_replay_lane_plan,
        "mixed_skill_workflow_secondary_lane_status": mixed_probe_status,
        "rows": rows,
        "diagnostics": sorted(dict.fromkeys(diagnostics)),
        "required_validation": skill_route_discovery_preactivation_validation_commands(),
        "provider_runtime_replay_commands": [
            PROVIDER_RUNTIME_PREFLIGHT_COMMAND,
            PROVIDER_RUNTIME_RECOVERY_SUMMARY_COMMAND,
        ],
        "local_validation_required": True,
        "body_free": True,
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass1_focused_evidence_review_lane(
    *,
    raw_input: dict[str, Any],
    pass1_validation_queue: dict[str, Any],
    profile_lane_acceptance_contract: dict[str, Any],
    validation_lane_plan: dict[str, Any],
) -> dict[str, Any]:
    """Expose active pass-1 proposal/profile lane checks before activation."""

    from blackhole_agent.skill_routing import SKILL_ROUTE_DISCOVERY_ALLOWED_LANES

    window = raw_input.get("capability_window")
    window = window if isinstance(window, dict) else {}
    current_pass = int(window.get("current_pass") or window.get("planned_pass") or 0)
    anchoring_proposals = string_list(window.get("anchoring_proposals"))
    allowed_lanes = set(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES)
    queue_rows = pass1_validation_queue.get("rows")
    queue_rows = queue_rows if isinstance(queue_rows, list) else []
    queue_rows_by_id = {
        optional_string(row.get("proposal_id")) or "": row
        for row in queue_rows
        if isinstance(row, dict) and optional_string(row.get("proposal_id"))
    }
    profile_rows = profile_lane_acceptance_contract.get("rows")
    profile_rows = profile_rows if isinstance(profile_rows, list) else []
    profile_rows_by_name = {
        optional_string(row.get("route_profile")) or "generic_skill_workflow": row
        for row in profile_rows
        if isinstance(row, dict)
    }
    plan_rows = validation_lane_plan.get("rows")
    plan_rows = plan_rows if isinstance(plan_rows, list) else []
    plan_rows_by_profile = {
        optional_string(row.get("route_profile")) or "generic_skill_workflow": row
        for row in plan_rows
        if isinstance(row, dict)
    }

    rows: list[dict[str, Any]] = []
    diagnostics: list[str] = []
    for proposal_id in anchoring_proposals:
        if _skill_route_discovery_is_general_agent_ref(proposal_id.casefold()):
            continue
        expected_profile, expected_lane = skill_route_discovery_pass1_expected_profile_lane(proposal_id)
        queue_row = queue_rows_by_id.get(proposal_id)
        queue_row_diagnostics = string_list(queue_row.get("diagnostics")) if isinstance(queue_row, dict) else []
        if not queue_row or "anchoring_proposal_not_in_replay_queue" in queue_row_diagnostics:
            contract_row = profile_rows_by_name.get(expected_profile, {})
            plan_row = plan_rows_by_profile.get(expected_profile, {})
            selected_lane = optional_string(contract_row.get("selected_first_local_lane")) or "none"
            validation_gate = optional_string(contract_row.get("validation_gate")) or ""
            row_diagnostics: list[str] = []
            if not contract_row:
                row_diagnostics.append("profile_acceptance_contract_missing")
            if selected_lane not in allowed_lanes:
                row_diagnostics.append("selected_local_lane_not_bounded")
            if expected_lane and selected_lane != expected_lane:
                row_diagnostics.append("selected_local_lane_does_not_match_profile_expectation")
            if not validation_gate:
                row_diagnostics.append("validation_gate_missing")
            if contract_row.get("local_validation_required") is not True:
                row_diagnostics.append("local_validation_not_required")
            if str(contract_row.get("runtime_action") or "none") != "none":
                row_diagnostics.append("runtime_action_requested")
            if contract_row.get("external_skill_activation_allowed") is not False:
                row_diagnostics.append("external_skill_activation_not_denied")
            if contract_row.get("external_harness_execution_allowed") is not False:
                row_diagnostics.append("external_harness_execution_not_denied")
            row_diagnostics = sorted(dict.fromkeys(row_diagnostics))
            diagnostics.extend(f"{stable_text_hash(proposal_id)}:{diagnostic}" for diagnostic in row_diagnostics)
            rows.append(
                {
                    "proposal_id": proposal_id,
                    "status": "ready" if not row_diagnostics else "blocked",
                    "selected_local_lane": selected_lane,
                    "expected_local_lane": expected_lane,
                    "route_profiles": [expected_profile] if expected_profile else [],
                    "expected_route_profile": expected_profile,
                    "validation_gates": [validation_gate] if validation_gate else [],
                    "evidence_ref_mode": "selected_item_ids_only",
                    "evidence_item_ids": string_list(plan_row.get("evidence_item_ids")) or [proposal_id],
                    "candidate_source_hashes": string_list(plan_row.get("candidate_source_hashes")),
                    "candidate_source_count": len(string_list(plan_row.get("candidate_source_hashes"))),
                    "diagnostics": row_diagnostics,
                    "local_validation_required": True,
                    "runtime_action": "none",
                    "runtime_action_allowed": False,
                    "external_skill_activation_allowed": False,
                    "external_harness_execution_allowed": False,
                    "provider_runtime_launch_allowed": False,
                    "remote_execution_allowed": False,
                    "raw_evidence_urls_exported": False,
                    "raw_source_urls_exported": False,
                    "raw_upstream_body_exported": False,
                }
            )
            continue

        selected_lane = optional_string(queue_row.get("selected_local_lane")) or "none"
        route_profiles = string_list(queue_row.get("route_profiles"))
        validation_gates = [
            optional_string(contract.get("validation_gate")) or ""
            for contract in (
                queue_row.get("profile_contracts")
                if isinstance(queue_row.get("profile_contracts"), list)
                else []
            )
            if isinstance(contract, dict) and optional_string(contract.get("validation_gate"))
        ]
        row_diagnostics = string_list(queue_row.get("diagnostics"))
        if selected_lane not in allowed_lanes:
            row_diagnostics.append("selected_local_lane_not_bounded")
        if expected_lane and selected_lane != expected_lane:
            row_diagnostics.append("selected_local_lane_does_not_match_profile_expectation")
        if expected_profile and expected_profile not in route_profiles:
            row_diagnostics.append("expected_route_profile_missing")
        if not route_profiles:
            row_diagnostics.append("route_profile_missing")
        if not validation_gates:
            row_diagnostics.append("validation_gate_missing")
        if queue_row.get("local_validation_required") is not True:
            row_diagnostics.append("local_validation_not_required")
        if str(queue_row.get("runtime_action") or "none") != "none":
            row_diagnostics.append("runtime_action_requested")
        if queue_row.get("external_skill_activation_allowed") is not False:
            row_diagnostics.append("external_skill_activation_not_denied")
        if queue_row.get("external_harness_execution_allowed") is not False:
            row_diagnostics.append("external_harness_execution_not_denied")
        if queue_row.get("provider_runtime_launch_allowed") is not False:
            row_diagnostics.append("provider_runtime_launch_not_denied")
        if queue_row.get("remote_execution_allowed") is not False:
            row_diagnostics.append("remote_execution_not_denied")

        row_diagnostics = sorted(dict.fromkeys(row_diagnostics))
        diagnostics.extend(f"{stable_text_hash(proposal_id)}:{diagnostic}" for diagnostic in row_diagnostics)
        rows.append(
            {
                "proposal_id": proposal_id,
                "status": "ready" if not row_diagnostics else "blocked",
                "selected_local_lane": selected_lane,
                "expected_local_lane": expected_lane,
                "route_profiles": route_profiles,
                "expected_route_profile": expected_profile,
                "validation_gates": sorted(dict.fromkeys(validation_gates)),
                "evidence_ref_mode": "selected_item_ids_only",
                "evidence_item_ids": string_list(queue_row.get("evidence_item_ids")),
                "candidate_source_hashes": string_list(queue_row.get("candidate_source_hashes")),
                "candidate_source_count": len(string_list(queue_row.get("candidate_source_hashes"))),
                "diagnostics": row_diagnostics,
                "local_validation_required": True,
                "runtime_action": "none",
                "runtime_action_allowed": False,
                "external_skill_activation_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    ready = (
        current_pass == 1
        and bool(rows)
        and not diagnostics
    )
    return {
        "controller_surface": "skill_route_discovery_pass1_focused_evidence_review_lane",
        "status": "ready" if ready else "not_applicable" if current_pass != 1 else "blocked",
        "decision": "pass1_focused_skill_route_lanes_ready_for_replay"
        if ready
        else "repair_pass1_focused_skill_route_lanes_before_replay",
        "current_pass": current_pass,
        "total_passes": int(window.get("total_passes") or 0),
        "allowed_local_lanes": list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES),
        "proposal_ids": [row["proposal_id"] for row in rows],
        "proposal_count": len(rows),
        "ready_proposal_count": sum(1 for row in rows if row["status"] == "ready"),
        "selected_local_lanes": sorted({row["selected_local_lane"] for row in rows if row["selected_local_lane"]}),
        "route_profiles": sorted({profile for row in rows for profile in string_list(row.get("route_profiles"))}),
        "rows": rows,
        "diagnostics": sorted(dict.fromkeys(diagnostics)),
        "required_validation": skill_route_discovery_preactivation_validation_commands(),
        "local_validation_required": True,
        "body_free": True,
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass1_expected_profile_lane(proposal_id: str) -> tuple[str, str]:
    """Infer the expected local lane for current pass-1 proposal wording."""

    value = proposal_id.casefold()
    if any(marker in value for marker in ("threejs", "three-js", "game", "frontend")):
        return "game_frontend_workflow", "test"
    if any(marker in value for marker in ("ecosystem", "state", "handoff", "compass")):
        return "skill_ecosystem_state_handoff", "config"
    if "generic" in value or ("skill" in value and "workflow" in value):
        return "generic_skill_workflow", "documentation"
    return "", ""


def skill_route_discovery_pass1_route_registry_handoff(
    *,
    raw_input: dict[str, Any],
    lane_map: dict[str, Any],
    pass1_validation_queue: dict[str, Any],
) -> dict[str, Any]:
    """Expose pass-1 registry evidence as bounded lanes plus adjacent eval rows."""

    from blackhole_agent.skill_routing import SKILL_ROUTE_DISCOVERY_ALLOWED_LANES

    window = raw_input.get("capability_window")
    window = window if isinstance(window, dict) else {}
    current_pass = int(window.get("current_pass") or window.get("planned_pass") or 0)
    allowed_lanes = list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES)
    allowed_lane_set = set(allowed_lanes)
    active_lane = lane_map.get("active_pass1_evidence_lane")
    active_lane = active_lane if isinstance(active_lane, dict) else {}
    validation_matrix = lane_map.get("pass1_validation_matrix")
    validation_matrix = validation_matrix if isinstance(validation_matrix, dict) else {}
    active_rows = active_lane.get("rows")
    active_rows = active_rows if isinstance(active_rows, list) else []
    matrix_rows = validation_matrix.get("rows")
    matrix_rows = matrix_rows if isinstance(matrix_rows, list) else []
    pass1_rows = pass1_validation_queue.get("rows")
    pass1_rows = pass1_rows if isinstance(pass1_rows, list) else []
    queued_general_agent_ids = {
        optional_string(row.get("proposal_id")) or ""
        for row in pass1_rows
        if isinstance(row, dict) and row.get("route") == "agent_harness_eval_required"
    }
    window_general_agent_refs = [
        ref
        for ref in (
            string_list(window.get("evidence_urls"))
            + string_list(window.get("anchoring_proposals"))
        )
        if _skill_route_discovery_is_general_agent_ref(ref)
    ]

    skill_rows: list[dict[str, Any]] = []
    diagnostics: list[str] = []
    for raw_row in active_rows:
        row = raw_row if isinstance(raw_row, dict) else {}
        selected_lane = optional_string(row.get("selected_local_lane")) or ""
        evidence_item_ids = (
            string_list(row.get("evidence_item_ids"))
            or string_list(row.get("selected_evidence_item_ids"))
        )
        candidate_source_hashes = string_list(row.get("candidate_source_hashes"))
        candidate_source_hash = optional_string(row.get("candidate_source_hash"))
        if candidate_source_hash:
            candidate_source_hashes = sorted(dict.fromkeys([*candidate_source_hashes, candidate_source_hash]))
        validation_gates = string_list(row.get("validation_gates"))
        row_diagnostics = string_list(row.get("diagnostics"))
        if selected_lane not in allowed_lane_set:
            row_diagnostics.append("selected_local_lane_not_bounded")
        if row.get("runtime_action") != "none":
            row_diagnostics.append("runtime_action_not_none")
        if row.get("external_skill_activation_allowed") is not False:
            row_diagnostics.append("external_skill_activation_not_denied")
        diagnostics.extend(
            f"{stable_text_hash(optional_string(row.get('proposal_id')) or '')}:{diagnostic}"
            for diagnostic in row_diagnostics
        )
        skill_rows.append(
            {
                "proposal_id": optional_string(row.get("proposal_id")) or "",
                "route": "skill_route_discovery",
                "selected_local_lane": selected_lane,
                "allowed_local_lanes": allowed_lanes,
                "route_profiles": string_list(row.get("route_profiles")),
                "evidence_ref_mode": "selected_item_ids_only",
                "evidence_item_ids": evidence_item_ids,
                "evidence_item_id_count": len(evidence_item_ids),
                "candidate_source_hashes": candidate_source_hashes,
                "candidate_source_count": len(candidate_source_hashes),
                "profile_gates": validation_gates,
                "queue_role": optional_string(row.get("queue_role")) or "",
                "local_validation_required": True,
                "runtime_action": "none",
                "external_skill_activation_allowed": False,
                "external_agent_activation_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_target_paths_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    profile_rows: list[dict[str, Any]] = []
    for raw_matrix_row in matrix_rows:
        row = raw_matrix_row if isinstance(raw_matrix_row, dict) else {}
        selected_lane = optional_string(row.get("selected_local_lane")) or ""
        queued_lanes = [lane for lane in string_list(row.get("queued_local_lanes")) if lane in allowed_lane_set]
        available_lanes = sorted(dict.fromkeys([selected_lane, *queued_lanes]))
        for profile in string_list(row.get("route_profiles")) or ["generic_skill_workflow"]:
            profile_rows.append(
                {
                    "route_profile": profile,
                    "selected_local_lane": selected_lane,
                    "available_local_lanes": available_lanes,
                    "validation_gates": string_list(row.get("validation_gates")),
                    "validation_target": optional_string(row.get("validation_target")) or "",
                    "evidence_item_ids": string_list(row.get("selected_evidence_item_ids")),
                    "candidate_source_hashes": string_list(row.get("candidate_source_hashes"))
                    or (
                        [optional_string(row.get("candidate_source_hash"))]
                        if optional_string(row.get("candidate_source_hash"))
                        else []
                    ),
                    "lanes_bounded": set(available_lanes) <= allowed_lane_set,
                    "local_validation_required": True,
                    "runtime_action": "none",
                    "external_skill_activation_allowed": False,
                    "external_harness_execution_allowed": False,
                    "provider_runtime_launch_allowed": False,
                    "remote_execution_allowed": False,
                    "raw_evidence_urls_exported": False,
                    "raw_source_urls_exported": False,
                    "raw_upstream_body_exported": False,
                }
            )
    adjacent_rows = [
        {
            "proposal_id": proposal_id,
            "route": "agent_harness_eval_required",
            "primary_route": "agent_harness_eval_required",
            "skill_route_discovery_inherited": False,
            "allowed_local_lanes": ["documentation", "test", "code_patch"],
            "blocked_skill_route_lanes": allowed_lanes,
            "evidence_ref_mode": "selected_item_ids_only",
            "replay_commands": [SKILL_ROUTE_DISCOVERY_PREACTIVATION_HARNESS_COMMAND],
            "local_validation_required": True,
            "runtime_action": "none",
            "runtime_action_allowed": False,
            "external_skill_activation_allowed": False,
            "external_agent_activation_allowed": False,
            "external_harness_execution_allowed": False,
            "provider_runtime_launch_allowed": False,
            "remote_execution_allowed": False,
            "raw_evidence_exported": False,
            "raw_evidence_urls_exported": False,
            "raw_source_urls_exported": False,
            "raw_upstream_body_exported": False,
        }
        for proposal_id in sorted(id_ for id_ in queued_general_agent_ids if id_)
    ]
    if window_general_agent_refs and not adjacent_rows:
        adjacent_rows.append(
            {
                "proposal_id": "window-adjacent-general-agent-project",
                "route": "agent_harness_eval_required",
                "primary_route": "agent_harness_eval_required",
                "skill_route_discovery_inherited": False,
                "allowed_local_lanes": ["documentation", "test", "code_patch"],
                "blocked_skill_route_lanes": allowed_lanes,
                "evidence_ref_mode": "selected_item_ids_only",
                "source_ref_hashes": sorted({stable_text_hash(ref) for ref in window_general_agent_refs}),
                "source_ref_count": len(set(window_general_agent_refs)),
                "replay_commands": [SKILL_ROUTE_DISCOVERY_PREACTIVATION_HARNESS_COMMAND],
                "local_validation_required": True,
                "runtime_action": "none",
                "runtime_action_allowed": False,
                "external_skill_activation_allowed": False,
                "external_agent_activation_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    ready = (
        current_pass == 1
        and bool(skill_rows)
        and not diagnostics
        and all(row["selected_local_lane"] in allowed_lane_set for row in skill_rows)
        and all(row["skill_route_discovery_inherited"] is False for row in adjacent_rows)
    )
    return {
        "controller_surface": "skill_route_discovery_pass1_route_registry_handoff",
        "status": "ready" if ready else "not_applicable" if current_pass != 1 else "blocked",
        "decision": "pass1_registry_profiles_ready_for_bounded_local_validation"
        if ready
        else "repair_pass1_registry_handoff_before_validation",
        "current_pass": current_pass,
        "total_passes": int(window.get("total_passes") or 0),
        "allowed_local_lanes": allowed_lanes,
        "selected_local_lanes": sorted(
            {row["selected_local_lane"] for row in skill_rows if row["selected_local_lane"] in allowed_lane_set}
        ),
        "route_profiles": sorted(
            {profile for row in skill_rows for profile in string_list(row.get("route_profiles"))}
        ),
        "skill_route_row_count": len(skill_rows),
        "profile_row_count": len(profile_rows),
        "adjacent_general_agent_row_count": len(adjacent_rows),
        "rows": skill_rows,
        "profile_rows": profile_rows,
        "adjacent_general_agent_project_eval": {
            "status": "gated" if adjacent_rows else "not_present",
            "agent_harness_eval_required": bool(adjacent_rows),
            "skill_route_discovery_inherited": False,
            "rows": adjacent_rows,
            "allowed_local_lanes": ["documentation", "test", "code_patch"] if adjacent_rows else [],
            "blocked_skill_route_lanes": allowed_lanes if adjacent_rows else [],
            "replay_commands": [SKILL_ROUTE_DISCOVERY_PREACTIVATION_HARNESS_COMMAND]
            if adjacent_rows
            else [],
            "runtime_action": "none",
            "runtime_action_allowed": False,
            "external_skill_activation_allowed": False,
            "external_agent_activation_allowed": False,
            "external_harness_execution_allowed": False,
            "provider_runtime_launch_allowed": False,
            "remote_execution_allowed": False,
            "raw_evidence_exported": False,
            "raw_evidence_urls_exported": False,
            "raw_source_urls_exported": False,
            "raw_upstream_body_exported": False,
        },
        "diagnostics": sorted(dict.fromkeys(diagnostics)),
        "required_validation": [SKILL_ROUTE_DISCOVERY_VALIDATION_COMMAND],
        "agent_harness_eval_replay_commands": [SKILL_ROUTE_DISCOVERY_PREACTIVATION_HARNESS_COMMAND]
        if adjacent_rows
        else [],
        "local_validation_required": True,
        "body_free": True,
        "runtime_action": "none",
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_active_window_route_lane_matrix(
    *,
    raw_input: dict[str, Any],
    pass1_validation_queue: dict[str, Any],
    pass1_route_registry_handoff: dict[str, Any],
) -> dict[str, Any]:
    """Render the active pass-1 proposal matrix across skill and agent lanes."""

    from blackhole_agent.skill_routing import SKILL_ROUTE_DISCOVERY_ALLOWED_LANES

    window = raw_input.get("capability_window")
    window = window if isinstance(window, dict) else {}
    current_pass = int(window.get("current_pass") or window.get("planned_pass") or 0)
    allowed_skill_lanes = list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES)
    allowed_agent_eval_lanes = ["documentation", "test", "code_patch"]
    queue_rows = pass1_validation_queue.get("rows")
    queue_rows = queue_rows if isinstance(queue_rows, list) else []
    registry_rows = pass1_route_registry_handoff.get("rows")
    registry_rows = registry_rows if isinstance(registry_rows, list) else []
    profile_rows = pass1_route_registry_handoff.get("profile_rows")
    profile_rows = profile_rows if isinstance(profile_rows, list) else []
    adjacent_eval = pass1_route_registry_handoff.get("adjacent_general_agent_project_eval")
    adjacent_eval = adjacent_eval if isinstance(adjacent_eval, dict) else {}
    adjacent_rows = adjacent_eval.get("rows")
    adjacent_rows = adjacent_rows if isinstance(adjacent_rows, list) else []

    registry_by_proposal = {
        optional_string(row.get("proposal_id")) or "": row
        for row in registry_rows
        if isinstance(row, dict)
    }
    profile_rows_by_profile = {
        optional_string(row.get("route_profile")) or "generic_skill_workflow": row
        for row in profile_rows
        if isinstance(row, dict)
    }

    rows: list[dict[str, Any]] = []
    diagnostics: list[str] = []
    for queue_row in queue_rows:
        if not isinstance(queue_row, dict):
            continue
        proposal_id = optional_string(queue_row.get("proposal_id")) or ""
        route = optional_string(queue_row.get("route")) or ""
        if route == "skill_route_discovery":
            registry_row = registry_by_proposal.get(proposal_id, {})
            route_profiles = string_list(queue_row.get("route_profiles")) or string_list(
                registry_row.get("route_profiles")
            )
            selected_lane = optional_string(queue_row.get("selected_local_lane")) or "none"
            profile_validation_gates = sorted(
                {
                    gate
                    for profile in route_profiles
                    for gate in string_list(profile_rows_by_profile.get(profile, {}).get("validation_gates"))
                }
            )
            if not profile_validation_gates:
                profile_validation_gates = sorted(
                    {
                        gate
                        for contract in (
                            queue_row.get("profile_contracts")
                            if isinstance(queue_row.get("profile_contracts"), list)
                            else []
                        )
                        if isinstance(contract, dict)
                        for gate in [optional_string(contract.get("validation_gate")) or ""]
                        if gate
                    }
                )
            row_diagnostics = string_list(queue_row.get("diagnostics"))
            if selected_lane not in allowed_skill_lanes:
                row_diagnostics.append("selected_local_lane_not_bounded")
            if queue_row.get("local_validation_required") is not True:
                row_diagnostics.append("local_validation_not_required")
            if str(queue_row.get("runtime_action") or "none") != "none":
                row_diagnostics.append("runtime_action_requested")
            if queue_row.get("external_skill_activation_allowed") is not False:
                row_diagnostics.append("external_skill_activation_not_denied")
            diagnostics.extend(
                f"{stable_text_hash(proposal_id)}:{diagnostic}"
                for diagnostic in sorted(dict.fromkeys(row_diagnostics))
            )
            rows.append(
                {
                    "proposal_id": proposal_id,
                    "primary_route": "skill_route_discovery",
                    "route_profiles": route_profiles,
                    "selected_local_lane": selected_lane,
                    "allowed_local_lanes": allowed_skill_lanes,
                    "validation_gates": profile_validation_gates,
                    "evidence_ref_mode": "selected_item_ids_only",
                    "evidence_item_ids": string_list(queue_row.get("evidence_item_ids")),
                    "evidence_item_id_count": len(string_list(queue_row.get("evidence_item_ids"))),
                    "candidate_source_hashes": string_list(queue_row.get("candidate_source_hashes")),
                    "candidate_source_count": len(string_list(queue_row.get("candidate_source_hashes"))),
                    "agent_harness_eval_required": False,
                    "skill_route_discovery_candidate": True,
                    "skill_route_discovery_inherited": False,
                    "ready_for_local_replay": not row_diagnostics,
                    "diagnostics": sorted(dict.fromkeys(row_diagnostics)),
                    "replay_commands": string_list(queue_row.get("replay_commands")),
                    "provider_runtime_replay_commands": string_list(
                        queue_row.get("provider_runtime_replay_commands")
                    ),
                    "local_validation_required": True,
                    "runtime_action": "none",
                    "external_skill_activation_allowed": False,
                    "external_agent_activation_allowed": False,
                    "external_harness_execution_allowed": False,
                    "provider_runtime_launch_allowed": False,
                    "remote_execution_allowed": False,
                    "raw_evidence_exported": False,
                    "raw_evidence_urls_exported": False,
                    "raw_source_urls_exported": False,
                    "raw_target_paths_exported": False,
                    "raw_upstream_body_exported": False,
                }
            )
        elif route == "agent_harness_eval_required":
            rows.append(
                {
                    "proposal_id": proposal_id,
                    "primary_route": "agent_harness_eval_required",
                    "route_profiles": [],
                    "selected_local_lane": "none",
                    "allowed_local_lanes": allowed_agent_eval_lanes,
                    "blocked_skill_route_lanes": allowed_skill_lanes,
                    "validation_gates": ["agent_harness_eval_before_runtime_behavior"],
                    "evidence_ref_mode": "selected_item_ids_only",
                    "evidence_item_ids": [],
                    "evidence_item_id_count": 0,
                    "candidate_source_hashes": string_list(queue_row.get("candidate_source_hashes")),
                    "candidate_source_count": len(string_list(queue_row.get("candidate_source_hashes"))),
                    "agent_harness_eval_required": True,
                    "skill_route_discovery_inherited": False,
                    "ready_for_local_replay": False,
                    "diagnostics": ["agent_harness_eval_required_before_runtime_behavior"],
                    "replay_commands": [SKILL_ROUTE_DISCOVERY_PREACTIVATION_HARNESS_COMMAND],
                    "local_validation_required": True,
                    "runtime_action": "none",
                    "external_skill_activation_allowed": False,
                    "external_agent_activation_allowed": False,
                    "external_harness_execution_allowed": False,
                    "provider_runtime_launch_allowed": False,
                    "remote_execution_allowed": False,
                    "raw_evidence_exported": False,
                    "raw_evidence_urls_exported": False,
                    "raw_source_urls_exported": False,
                    "raw_target_paths_exported": False,
                    "raw_upstream_body_exported": False,
                }
            )

    queued_agent_ids = {
        optional_string(row.get("proposal_id")) or ""
        for row in rows
        if row.get("primary_route") == "agent_harness_eval_required"
    }
    for adjacent_row in adjacent_rows:
        if not isinstance(adjacent_row, dict):
            continue
        proposal_id = optional_string(adjacent_row.get("proposal_id")) or "window-adjacent-general-agent-project"
        if proposal_id in queued_agent_ids:
            continue
        rows.append(
            {
                "proposal_id": proposal_id,
                "primary_route": "agent_harness_eval_required",
                "route_profiles": [],
                "selected_local_lane": "none",
                "allowed_local_lanes": allowed_agent_eval_lanes,
                "blocked_skill_route_lanes": allowed_skill_lanes,
                "validation_gates": ["agent_harness_eval_before_runtime_behavior"],
                "evidence_ref_mode": "hashes_only",
                "evidence_item_ids": [],
                "evidence_item_id_count": 0,
                "candidate_source_hashes": string_list(adjacent_row.get("source_ref_hashes")),
                "candidate_source_count": len(string_list(adjacent_row.get("source_ref_hashes"))),
                "agent_harness_eval_required": True,
                "skill_route_discovery_inherited": False,
                "ready_for_local_replay": False,
                "diagnostics": ["agent_harness_eval_required_before_runtime_behavior"],
                "replay_commands": [SKILL_ROUTE_DISCOVERY_PREACTIVATION_HARNESS_COMMAND],
                "local_validation_required": True,
                "runtime_action": "none",
                "external_skill_activation_allowed": False,
                "external_agent_activation_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_target_paths_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    skill_rows = [row for row in rows if row["primary_route"] == "skill_route_discovery"]
    agent_rows = [row for row in rows if row["primary_route"] == "agent_harness_eval_required"]
    ready = (
        current_pass == 1
        and bool(skill_rows)
        and not diagnostics
        and all(row["selected_local_lane"] in allowed_skill_lanes for row in skill_rows)
        and all(row["local_validation_required"] is True for row in rows)
        and all(str(row["runtime_action"]) == "none" for row in rows)
        and all(row["external_skill_activation_allowed"] is False for row in rows)
        and all(row["external_harness_execution_allowed"] is False for row in rows)
        and all(row["skill_route_discovery_inherited"] is False for row in agent_rows)
    )

    return {
        "controller_surface": "skill_route_discovery_active_window_route_lane_matrix",
        "status": "ready" if ready else "not_applicable" if current_pass != 1 else "blocked",
        "decision": "active_window_routes_mapped_to_bounded_local_lanes"
        if ready
        else "repair_active_window_route_lanes_before_activation",
        "current_pass": current_pass,
        "total_passes": int(window.get("total_passes") or 0),
        "allowed_skill_route_lanes": allowed_skill_lanes,
        "allowed_agent_harness_eval_lanes": allowed_agent_eval_lanes,
        "row_count": len(rows),
        "skill_route_row_count": len(skill_rows),
        "agent_harness_eval_required_count": len(agent_rows),
        "selected_local_lanes": sorted(
            {row["selected_local_lane"] for row in skill_rows if row["selected_local_lane"] in allowed_skill_lanes}
        ),
        "route_profiles": sorted(
            {profile for row in skill_rows for profile in string_list(row.get("route_profiles"))}
        ),
        "proposal_ids": [row["proposal_id"] for row in rows if row["proposal_id"]],
        "rows": rows,
        "diagnostics": sorted(dict.fromkeys(diagnostics)),
        "required_validation": [SKILL_ROUTE_DISCOVERY_VALIDATION_COMMAND],
        "agent_harness_eval_replay_commands": [SKILL_ROUTE_DISCOVERY_PREACTIVATION_HARNESS_COMMAND]
        if agent_rows
        else [],
        "local_validation_required": bool(rows),
        "body_free": True,
        "runtime_action": "none",
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_active_window_activation_candidate_lane(
    *,
    active_window_route_lane_matrix: dict[str, Any],
) -> dict[str, Any]:
    """Summarize active pass-1 rows as bounded supervisor replay candidates."""

    from blackhole_agent.skill_routing import SKILL_ROUTE_DISCOVERY_ALLOWED_LANES

    allowed_skill_lanes = list(SKILL_ROUTE_DISCOVERY_ALLOWED_LANES)
    allowed_agent_eval_lanes = ["documentation", "test", "code_patch"]
    matrix_rows = active_window_route_lane_matrix.get("rows")
    matrix_rows = matrix_rows if isinstance(matrix_rows, list) else []
    diagnostics = string_list(active_window_route_lane_matrix.get("diagnostics"))

    rows: list[dict[str, Any]] = []
    for matrix_row in matrix_rows:
        if not isinstance(matrix_row, dict):
            continue
        primary_route = optional_string(matrix_row.get("primary_route")) or ""
        selected_lane = optional_string(matrix_row.get("selected_local_lane")) or "none"
        row_diagnostics = string_list(matrix_row.get("diagnostics"))
        if primary_route == "skill_route_discovery":
            lane_ready = (
                selected_lane in allowed_skill_lanes
                and matrix_row.get("ready_for_local_replay") is True
                and not row_diagnostics
            )
            activation_status = "candidate_ready" if lane_ready else "candidate_blocked"
            supervisor_replay_step = "replay_bounded_skill_route_validation_lane"
            activation_blockers = [] if lane_ready else sorted(dict.fromkeys(row_diagnostics or ["local_replay_not_ready"]))
        else:
            lane_ready = False
            activation_status = "blocked_adjacent_eval"
            supervisor_replay_step = "route_to_agent_harness_eval_after_skill_lane"
            activation_blockers = sorted(
                dict.fromkeys(row_diagnostics or ["agent_harness_eval_required_before_runtime_behavior"])
            )

        rows.append(
            {
                "proposal_id": optional_string(matrix_row.get("proposal_id")) or "",
                "primary_route": primary_route,
                "activation_status": activation_status,
                "supervisor_replay_step": supervisor_replay_step,
                "selected_local_lane": selected_lane,
                "allowed_local_lanes": string_list(matrix_row.get("allowed_local_lanes")),
                "route_profiles": string_list(matrix_row.get("route_profiles")),
                "validation_gates": string_list(matrix_row.get("validation_gates")),
                "evidence_ref_mode": optional_string(matrix_row.get("evidence_ref_mode")) or "selected_item_ids_only",
                "evidence_item_ids": string_list(matrix_row.get("evidence_item_ids")),
                "evidence_item_id_count": len(string_list(matrix_row.get("evidence_item_ids"))),
                "candidate_source_hashes": string_list(matrix_row.get("candidate_source_hashes")),
                "candidate_source_count": len(string_list(matrix_row.get("candidate_source_hashes"))),
                "activation_blockers": activation_blockers,
                "ready_for_supervisor_replay": lane_ready,
                "skill_route_discovery_inherited": matrix_row.get("skill_route_discovery_inherited") is True,
                "local_validation_required": True,
                "runtime_action": "none",
                "external_skill_activation_allowed": False,
                "external_agent_activation_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_target_paths_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    skill_rows = [row for row in rows if row["primary_route"] == "skill_route_discovery"]
    adjacent_rows = [row for row in rows if row["primary_route"] == "agent_harness_eval_required"]
    ready_skill_rows = [row for row in skill_rows if row["ready_for_supervisor_replay"] is True]
    ready = (
        active_window_route_lane_matrix.get("status") == "ready"
        and bool(skill_rows)
        and len(ready_skill_rows) == len(skill_rows)
        and not diagnostics
        and all(row["selected_local_lane"] in allowed_skill_lanes for row in skill_rows)
        and all(row["skill_route_discovery_inherited"] is False for row in adjacent_rows)
    )

    return {
        "controller_surface": "skill_route_discovery_active_window_activation_candidate_lane",
        "status": "ready" if ready else "blocked",
        "decision": "active_pass1_skill_route_candidates_ready_for_supervisor_replay"
        if ready
        else "repair_active_pass1_activation_candidates_before_supervisor_replay",
        "current_pass": int(active_window_route_lane_matrix.get("current_pass") or 0),
        "total_passes": int(active_window_route_lane_matrix.get("total_passes") or 0),
        "candidate_count": len(rows),
        "ready_candidate_count": len(ready_skill_rows),
        "blocked_candidate_count": len(rows) - len(ready_skill_rows),
        "skill_route_candidate_count": len(skill_rows),
        "adjacent_eval_candidate_count": len(adjacent_rows),
        "selected_local_lanes": sorted(
            {row["selected_local_lane"] for row in skill_rows if row["selected_local_lane"] in allowed_skill_lanes}
        ),
        "allowed_skill_route_lanes": allowed_skill_lanes,
        "allowed_agent_harness_eval_lanes": allowed_agent_eval_lanes,
        "route_profiles": sorted(
            {profile for row in skill_rows for profile in string_list(row.get("route_profiles"))}
        ),
        "proposal_ids": [row["proposal_id"] for row in rows if row["proposal_id"]],
        "supervisor_next_action": "replay_ready_skill_route_lanes_then_gate_adjacent_eval"
        if adjacent_rows
        else "replay_ready_skill_route_lanes",
        "rows": rows,
        "diagnostics": diagnostics,
        "required_validation": [SKILL_ROUTE_DISCOVERY_VALIDATION_COMMAND],
        "agent_harness_eval_replay_commands": [SKILL_ROUTE_DISCOVERY_PREACTIVATION_HARNESS_COMMAND]
        if adjacent_rows
        else [],
        "local_validation_required": bool(rows),
        "body_free": True,
        "runtime_action": "none",
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


def skill_route_discovery_pass1_replay_lane_plan(
    *,
    current_pass: int,
    total_passes: int,
    ready: bool,
    pass_validation_replay_queue: dict[str, Any],
    profile_validation_lanes: list[dict[str, Any]],
) -> dict[str, Any]:
    """Build an operator replay plan from the pass-1 queue rows."""

    queue_rows = pass_validation_replay_queue.get("rows")
    queue_rows = queue_rows if isinstance(queue_rows, list) else []
    profile_rows_by_name = {
        optional_string(row.get("route_profile")) or "generic_skill_workflow": row
        for row in profile_validation_lanes
        if isinstance(row, dict)
    }
    rows: list[dict[str, Any]] = []
    diagnostics: list[str] = []

    for queue_row in queue_rows:
        if not isinstance(queue_row, dict):
            continue
        route_profiles = string_list(queue_row.get("route_profiles"))
        profile_rows = [profile_rows_by_name[profile] for profile in route_profiles if profile in profile_rows_by_name]
        validation_gates = sorted(
            {
                gate
                for profile_row in profile_rows
                for gate in [optional_string(profile_row.get("validation_gate")) or ""]
                if gate
            }
        )
        row_diagnostics: list[str] = []
        if not profile_rows:
            row_diagnostics.append("profile_validation_lane_missing")
        if queue_row.get("local_validation_required") is not True:
            row_diagnostics.append("local_validation_not_required")
        if str(queue_row.get("runtime_action") or "none") != "none":
            row_diagnostics.append("runtime_action_requested")
        if queue_row.get("external_skill_activation_allowed") is not False:
            row_diagnostics.append("external_skill_activation_not_denied")
        if queue_row.get("external_harness_execution_allowed") is not False:
            row_diagnostics.append("external_harness_execution_not_denied")
        diagnostics.extend(f"{int(queue_row.get('queue_position') or 0)}:{diagnostic}" for diagnostic in row_diagnostics)
        rows.append(
            {
                "queue_position": int(queue_row.get("queue_position") or len(rows) + 1),
                "queue_role": optional_string(queue_row.get("queue_role")) or "queued_bounded_lane",
                "selected_local_lane": optional_string(queue_row.get("selected_local_lane")) or "none",
                "route_profiles": route_profiles,
                "validation_gates": validation_gates,
                "evidence_item_ids": string_list(queue_row.get("evidence_item_ids")),
                "evidence_item_id_count": len(string_list(queue_row.get("evidence_item_ids"))),
                "candidate_source_hashes": string_list(queue_row.get("candidate_source_hashes")),
                "candidate_source_count": len(string_list(queue_row.get("candidate_source_hashes"))),
                "queue_fingerprint": optional_string(queue_row.get("queue_fingerprint")) or "",
                "fingerprint_basis": optional_string(queue_row.get("fingerprint_basis")) or "",
                "replay_commands": string_list(queue_row.get("replay_commands")),
                "provider_runtime_replay_commands": string_list(queue_row.get("provider_runtime_replay_commands")),
                "first_route_required": any(row.get("first_route_required") is True for row in profile_rows),
                "first_route_confirmed": any(row.get("first_route_confirmed") is True for row in profile_rows),
                "queue_status": "ready" if not row_diagnostics else "blocked",
                "diagnostics": sorted(dict.fromkeys(row_diagnostics)),
                "local_validation_required": True,
                "runtime_action": "none",
                "external_skill_activation_allowed": False,
                "external_agent_activation_allowed": False,
                "external_harness_execution_allowed": False,
                "provider_runtime_launch_allowed": False,
                "remote_execution_allowed": False,
                "raw_evidence_exported": False,
                "raw_evidence_urls_exported": False,
                "raw_source_urls_exported": False,
                "raw_target_paths_exported": False,
                "raw_upstream_body_exported": False,
            }
        )

    return {
        "controller_surface": "skill_route_discovery_pass1_replay_lane_plan",
        "status": "ready" if current_pass == 1 and ready and rows and not diagnostics else "blocked",
        "decision": "replay_pass1_current_lane_then_queued_profile_lanes"
        if current_pass == 1 and ready and rows and not diagnostics
        else "repair_pass1_replay_lane_plan_before_activation",
        "current_pass": current_pass,
        "total_passes": total_passes,
        "replay_step_count": len(rows),
        "selected_current_pass_profiles": sorted(
            {
                profile
                for row in rows
                if row["queue_role"] == "selected_current_pass_lane"
                for profile in string_list(row.get("route_profiles"))
            }
        ),
        "queued_profile_count": sum(1 for row in rows if row["queue_role"] == "queued_bounded_lane"),
        "queued_profiles": sorted(
            {
                profile
                for row in rows
                if row["queue_role"] == "queued_bounded_lane"
                for profile in string_list(row.get("route_profiles"))
            }
        ),
        "selected_local_lanes": sorted({row["selected_local_lane"] for row in rows if row["selected_local_lane"]}),
        "evidence_ref_mode": "selected_item_ids_only",
        "rows": rows,
        "diagnostics": sorted(dict.fromkeys(diagnostics)),
        "local_validation_required": bool(rows),
        "body_free": True,
        "runtime_action_allowed": False,
        "external_skill_activation_allowed": False,
        "external_agent_activation_allowed": False,
        "external_harness_execution_allowed": False,
        "provider_runtime_launch_allowed": False,
        "remote_execution_allowed": False,
        "raw_evidence_exported": False,
        "raw_evidence_urls_exported": False,
        "raw_source_urls_exported": False,
        "raw_target_paths_exported": False,
        "raw_upstream_body_exported": False,
    }


